const QUESTIONS_ECIH_C3 = [
  { id:80501, domain:3, level:1, question:"Which malware type replicates by attaching its code to legitimate host files or programs?", options:["A virus, which inserts its code into host files and executes when the infected file is run","A worm, which self-propagates across networks without needing any host file to attach to","A rootkit, which mainly hides its presence deep within the operating system kernel space","Adware, which chiefly displays unwanted advertisements rather than infecting any host files"], correct:0, explanation:"A virus needs a host file to spread; a worm is wrong because worms self-propagate without attaching to host files." },
  { id:80502, domain:3, level:1, question:"Which malware self-propagates across networks without requiring a host file or user action?", options:["A virus, which requires a host file and a user to execute the infected program to spread it","A worm, which independently copies itself to other systems by exploiting network services","A trojan, which disguises itself as legitimate software and relies on the user to run it","Spyware, which secretly gathers user information rather than propagating across the network"], correct:1, explanation:"Worms self-replicate over networks autonomously; a virus is wrong because it depends on a host file and user execution." },
  { id:80503, domain:3, level:1, question:"Which malware disguises itself as legitimate software to trick users into installing it?", options:["A worm, which spreads automatically across networks without disguising as legitimate apps","A rootkit, whose primary purpose is concealment rather than masquerading as useful software","A trojan, which appears to be a useful program but carries hidden malicious functionality","A botnet, which is a network of compromised hosts controlled by a remote command server"], correct:2, explanation:"A trojan relies on disguise and social engineering; a worm is wrong because worms spread automatically, not by masquerade." },
  { id:80504, domain:3, level:1, question:"Which malware encrypts a victim's files and demands payment for the decryption key?", options:["Spyware, which covertly monitors activity and steals data without encrypting victim files","Adware, which displays intrusive advertisements but does not encrypt or lock user data","A keylogger, which records keystrokes to capture credentials rather than encrypting files","Ransomware, which encrypts data and demands a ransom in exchange for the decryption key"], correct:3, explanation:"Ransomware's defining trait is encrypting files for extortion; spyware is wrong because it steals data quietly, not by encryption." },
  { id:80505, domain:3, level:1, question:"Which malware is specifically designed to hide its presence and maintain privileged access?", options:["A rootkit, which conceals files, processes, and itself while retaining privileged system access","Adware, which openly displays advertisements and does not attempt to hide from the user in this case","A worm, whose main behavior is rapid self-propagation rather than stealthy concealment","Ransomware, which announces itself with a ransom note rather than hiding on the system"], correct:0, explanation:"Rootkits specialize in stealth and privilege retention; adware is wrong because it is overt, not hidden." },
  { id:80506, domain:3, level:1, question:"Which malware secretly collects information about a user's activity and sends it to attackers?", options:["A worm, which self-replicates across networks rather than covertly collecting user data","Spyware, which covertly gathers user data and activity and transmits it to a remote party","Ransomware, which locks or encrypts files for extortion instead of quietly exfiltrating data","A rootkit, which focuses on hiding malicious components rather than harvesting user activity"], correct:1, explanation:"Spyware is defined by covert data collection; a worm is wrong because propagation, not surveillance, is its purpose." },
  { id:80507, domain:3, level:1, question:"What term describes a network of compromised computers remotely controlled by an attacker?", options:["A honeypot, which is a decoy system deliberately deployed to attract and study attackers","A sandbox, which is an isolated environment used to safely execute and analyze malware code in this case","A botnet, a collection of infected hosts (bots) controlled through a command-and-control server","A rootkit, which is a single stealth toolkit rather than a network of controlled machines"], correct:2, explanation:"A botnet is many controlled hosts; a honeypot is wrong because it is a defensive decoy, not attacker infrastructure." },
  { id:80508, domain:3, level:1, question:"Which malware provides an attacker with interactive remote control over an infected system?", options:["Adware, which serves advertisements and does not grant remote control of the infected host","A logic bomb, which triggers a payload on a condition rather than granting ongoing remote control","A macro virus, which spreads through document macros rather than providing remote access","A Remote Access Trojan (RAT), which gives an attacker interactive remote control of the host"], correct:3, explanation:"A RAT grants covert remote control; adware is wrong because it only shows ads and offers no remote access." },
  { id:80509, domain:3, level:1, question:"What is fileless malware best characterized by?", options:["Malware that operates in memory using legitimate tools and leaves few artifacts on disk","Malware that always writes a large encrypted executable to the hard drive before running","Malware that spreads only through infected USB drives and never uses system memory at all","Malware that can only run inside a browser tab and cannot touch the host operating system"], correct:0, explanation:"Fileless malware lives in memory and abuses legitimate tools; the disk-executable option is wrong because it defeats the fileless nature." },
  { id:80510, domain:3, level:1, question:"Which type of malware displays unwanted advertisements, often bundled with free software?", options:["A rootkit, which hides deep in the system rather than showing advertisements to the user","Adware, which presents unwanted advertisements and is frequently bundled with free downloads","A worm, which propagates across networks rather than presenting advertising content to users","Ransomware, which encrypts files for payment rather than merely displaying advertisements"], correct:1, explanation:"Adware's hallmark is unwanted ads; a rootkit is wrong because its purpose is concealment, not advertising." },
  { id:80511, domain:3, level:1, question:"What is a keylogger primarily designed to do on an infected system?", options:["Encrypt the user's documents and demand a ransom payment for the decryption key needed","Broadcast advertisements in the browser to generate revenue for the malware's author","Record the user's keystrokes to capture credentials and other sensitive typed information","Self-replicate rapidly across the local network by exploiting open file-sharing services in this case"], correct:2, explanation:"A keylogger captures typed input like passwords; the encryption option is wrong because that describes ransomware, not keylogging." },
  { id:80512, domain:3, level:1, question:"What does a dropper do in a malware infection chain?", options:["It permanently encrypts the entire hard drive before any other malware component runs","It only displays a decoy error message and performs no further malicious actions at all","It serves as a legitimate signed antivirus updater that cleans the host during infection","It installs or downloads additional malicious payloads onto the compromised host system"], correct:3, explanation:"A dropper delivers additional payloads; the encryption option is wrong because encrypting the drive describes ransomware behavior, not a dropper." },
  { id:80513, domain:3, level:1, question:"What is a macro virus?", options:["Malware written in a document's macro language that runs when the document is opened","A hardware chip virus that infects the CPU microcode and cannot be removed by software","A firewall rule set that automatically blocks all inbound macro-enabled document traffic","A benign automation script that only formats spreadsheets and never behaves maliciously"], correct:0, explanation:"Macro viruses live in document macros and run on open; the CPU-microcode option is wrong and not how macro viruses work." },
  { id:80514, domain:3, level:1, question:"Which term describes malicious software as a broad general category?", options:["Firmware, the low-level software permanently written to a hardware device's memory chips","Malware, an umbrella term for any software created to harm, exploit, or compromise systems","Middleware, software that connects applications and services within an enterprise system","Shareware, software distributed freely on a trial basis before an optional purchase later in this case"], correct:1, explanation:"Malware is the umbrella term for malicious software; firmware is wrong because it is legitimate device software, not malicious code." },
  { id:80515, domain:3, level:1, question:"What is command-and-control (C2) infrastructure in the context of malware?", options:["The internal help desk that users contact when they suspect their machine is infected","A backup system that stores clean copies of files to recover from malware infections later in this case","Servers attackers use to send instructions to and receive data from infected hosts remotely","The antivirus management console administrators use to push signature updates to endpoints"], correct:2, explanation:"C2 is attacker infrastructure that controls infected hosts; the help-desk option is wrong because it is an internal support function, not attacker control." },
  { id:80516, domain:3, level:1, question:"What is a potentially unwanted program (PUP)?", options:["A critical operating system service that must always run for the computer to boot correctly","A digitally signed security patch issued by the vendor to fix a known vulnerability quickly","A mandatory enterprise agent that enforces the organization's endpoint security baseline","Software bundled with downloads that may be unwanted, such as toolbars or aggressive adware"], correct:3, explanation:"A PUP is bundled, often unwanted software like toolbars; a critical OS service is wrong because it is essential legitimate software, not a PUP." },
  { id:80517, domain:3, level:1, question:"Which malware component is designed to keep the malware running after a reboot?", options:["A persistence mechanism, such as a registry autorun key, service, or scheduled task entry","A packer, which compresses and obfuscates the malware to evade signature-based detection","A ransom note, which is a text file instructing the victim on how to pay the demanded ransom","A beacon, which is the periodic signal an infected host sends to its command-and-control server"], correct:0, explanation:"Persistence mechanisms survive reboots; a packer is wrong because it obfuscates the file rather than maintaining execution across restarts." },
  { id:80518, domain:3, level:1, question:"What is a wiper?", options:["A cleaning utility that safely removes temporary files to free space on the hard drive","Malware whose goal is to destroy or irreversibly corrupt data rather than extort payment","A backup agent that securely erases old snapshots after a successful retention rotation","A firewall feature that wipes malicious packets from the network before they reach hosts"], correct:1, explanation:"A wiper destroys data with no recovery intent; a cleaning utility is wrong because it is a benign maintenance tool, not destructive malware." },
  { id:80519, domain:3, level:1, question:"What is a zero-day exploit as used by malware?", options:["An exploit that only functions on the exact calendar day the software was first released","A vulnerability that has been publicly patched for zero days and no longer poses any risk","An attack that leverages a vulnerability unknown to the vendor and lacking an available patch","An antivirus signature that detects malware within zero days of the sample being submitted in this case"], correct:2, explanation:"A zero-day targets an unpatched, unknown flaw; the calendar-day option is wrong because 'zero-day' refers to no available fix, not a release date." },
  { id:80520, domain:3, level:1, question:"Which of these is an example of a common malware delivery method?", options:["A firewall rule that denies all inbound connections from untrusted external IP addresses","A multi-factor authentication prompt that verifies a user's identity before granting access","A scheduled backup job that copies critical data to an offline storage location each night","A malicious email attachment disguised as an invoice that installs malware when opened"], correct:3, explanation:"A malicious attachment is a delivery method; a firewall rule is wrong because it is a protective control, not a way malware is delivered." },
  { id:80521, domain:3, level:2, question:"In the ECIH malware incident handling process, what should be completed before an incident occurs?", options:["Preparation, which establishes tools, policies, and trained staff to handle malware incidents","Eradication, which removes the malware only after the infection has already been contained in this case","Recovery, which restores systems to normal operation after the threat has been eliminated","Post-incident activity, which captures lessons learned once the incident is fully resolved"], correct:0, explanation:"Preparation happens before incidents; eradication is wrong because it occurs after detection and containment, not beforehand." },
  { id:80522, domain:3, level:2, question:"During a malware incident, what is the primary goal of the containment phase?", options:["Permanently removing every trace of the malware from all of the affected systems immediately","Limiting the spread and impact of the malware to prevent further damage across the systems","Restoring business operations to full normal capacity as quickly as possible for all the users","Documenting the timeline and lessons learned for the final post-incident report to management"], correct:1, explanation:"Containment limits spread; permanent removal describes eradication, which is a distinct later phase, not containment's goal." },
  { id:80523, domain:3, level:2, question:"Which action best represents short-term containment of a malware-infected workstation?", options:["Rebuilding the workstation from a known-good image before any evidence is preserved at all","Applying all outstanding operating system patches across the entire enterprise fleet at once","Isolating the infected host from the network to stop the malware communicating or spreading","Writing the final incident report and distributing lessons learned to executive stakeholders"], correct:2, explanation:"Isolating the host is immediate short-term containment; rebuilding first is wrong because it destroys evidence prematurely." },
  { id:80524, domain:3, level:2, question:"Why should an infected system's memory be captured before powering it off during analysis?", options:["Powering off the system automatically encrypts the disk and prevents any later forensic access in this case","Memory capture is only needed for hardware failures and has no relevance to malware analysis","The operating system rewrites all the log files during shutdown, so memory capture is needless","Volatile memory holds fileless malware artifacts and encryption keys lost when power is removed"], correct:3, explanation:"RAM contains volatile evidence like keys and fileless code; the auto-encrypt claim is wrong and not how shutdown behaves." },
  { id:80525, domain:3, level:2, question:"What is the recommended first response when ransomware is detected actively encrypting files?", options:["Immediately isolate the affected system from the network to halt further encryption and spread","Pay the ransom promptly to obtain the decryption key and minimize business downtime costs now","Reboot the machine repeatedly until the encryption process stops on its own without any action","Delete all encrypted files right away to free disk space before restoring from any known backup"], correct:0, explanation:"Isolation stops spread and further encryption; paying the ransom is wrong because it funds crime and does not guarantee recovery." },
  { id:80526, domain:3, level:2, question:"What is EC-Council's general guidance regarding paying a ransomware ransom?", options:["Always pay quickly because attackers reliably provide working decryption keys after any payment","Avoid paying, as payment funds criminals and offers no guarantee that data will be recovered","Pay only if the ransom is under a fixed dollar amount defined by international regulations today","Pay and then immediately reconnect the host to the network to speed up the recovery process"], correct:1, explanation:"Do-not-pay is the guidance since payment is unreliable and funds crime; 'always pay' is wrong because keys are not guaranteed." },
  { id:80527, domain:3, level:2, question:"What is the most reliable way to recover data after a ransomware attack without paying?", options:["Run a standard antivirus scan, which will automatically decrypt all of the encrypted files","Rename the encrypted file extensions back to their originals to make the files readable again in this case","Restore the affected data from clean, offline backups verified to be free of the malware itself","Reboot into safe mode, which reverses the encryption performed by the ransomware payload code"], correct:2, explanation:"Clean offline backups enable recovery without paying; AV scanning is wrong because it removes malware but cannot decrypt files." },
  { id:80528, domain:3, level:2, question:"Why are offline or immutable backups emphasized for ransomware resilience?", options:["Offline backups run faster than online ones, which is the main reason they are recommended","Immutable backups automatically decrypt any ransomware they encounter during a live restore","Offline backups eliminate the need for any endpoint protection on production servers entirely","Ransomware often seeks and encrypts network-connected backups, which offline copies avoid"], correct:3, explanation:"Offline/immutable backups escape encryption of reachable backups; the auto-decrypt claim is wrong and not a backup function." },
  { id:80529, domain:3, level:2, question:"Which of these is a common malware infection vector in enterprise environments?", options:["Phishing emails carrying malicious attachments or links that users are tricked into opening","Correctly configured firewalls that deny all inbound traffic from untrusted external networks","Regularly patched systems that have no known exploitable vulnerabilities remaining on them","Multi-factor authentication enforced consistently across all remote administrative accounts"], correct:0, explanation:"Phishing is a leading infection vector; hardened firewalls, patching, and MFA are controls that reduce infection, not vectors." },
  { id:80530, domain:3, level:2, question:"Which behavior is a typical indicator that a host may be infected with malware?", options:["Antivirus definitions updating automatically on the normal scheduled maintenance window daily","Unexpected outbound connections to unknown external IP addresses and unusual spikes in traffic","A user successfully logging in during business hours from their assigned corporate laptop today","Scheduled backups completing successfully every night without any reported errors at all times"], correct:1, explanation:"Unexpected outbound connections suggest C2 activity; routine AV updates are wrong because they are normal, healthy behavior." },
  { id:80531, domain:3, level:2, question:"What does IOC stand for in the context of malware detection?", options:["Instance of Containment, a formal record kept when a host is isolated during an incident","Internal Operations Center, the physical facility where the response team coordinates work in this case","Indicator of Compromise, an artifact observed that suggests a system has been intruded upon","Isolated Object Cache, a memory region that malware uses to hide its persistent components"], correct:2, explanation:"IOC means Indicator of Compromise; the other expansions are invented and not standard incident-response terminology." },
  { id:80532, domain:3, level:2, question:"Which of the following is an example of a host-based indicator of compromise?", options:["A signed vendor driver installed by the operating system's normal automatic update process","A routine DNS lookup to the organization's internal, trusted, and monitored name servers","A user changing their own password through the approved self-service password portal page","An unexpected new service, registry autorun entry, or unknown scheduled task on a system"], correct:3, explanation:"New autorun/registry/service entries are host IOCs; a signed vendor driver from normal updates is wrong because it is expected." },
  { id:80533, domain:3, level:2, question:"What distinguishes static malware analysis from dynamic malware analysis?", options:["Static analysis examines the sample without executing it, while dynamic runs it to see behavior","Static analysis always requires running the malware in a live production environment first","Dynamic analysis never involves executing the sample and only reads its file header bytes","Static and dynamic analysis are identical terms describing the same signature-matching process in this case"], correct:0, explanation:"Static inspects without execution while dynamic executes to observe; the claim they are identical is wrong." },
  { id:80534, domain:3, level:2, question:"Why is a sandbox used when analyzing suspected malware?", options:["It permanently deletes the malware sample immediately so it can never be analyzed at all","It provides an isolated environment to execute the sample safely and observe its behavior","It guarantees that the malware will reveal its full source code in a readable text format","It connects the sample directly to production systems to observe real business impact live"], correct:1, explanation:"A sandbox isolates execution to observe behavior safely; connecting it to production is wrong because that risks real damage." },
  { id:80535, domain:3, level:2, question:"Which technique do some malware samples use to evade sandbox-based analysis?", options:["Immediately printing their full configuration to the screen whenever a sandbox is detected","Automatically uploading themselves to public antivirus repositories for faster classification in this case","Detecting virtualized or analysis environments and staying dormant to avoid revealing behavior","Disabling their own network features so analysts can more easily study their capabilities"], correct:2, explanation:"Sandbox-aware malware detects analysis environments and lies dormant; the self-disclosure options are wrong because they aid, not evade, analysis." },
  { id:80536, domain:3, level:2, question:"What is the purpose of the eradication phase in malware incident handling?", options:["Isolating the infected host from the network to temporarily stop the malware from spreading in this case","Capturing volatile memory and disk images to preserve evidence for later forensic analysis","Notifying executives and regulators about the incident and its estimated financial impact","Removing the malware and its artifacts, then closing the vulnerabilities that allowed infection"], correct:3, explanation:"Eradication removes malware and closes the entry point; isolating the host describes containment, a separate earlier phase." },
  { id:80537, domain:3, level:2, question:"During eradication, why is simply deleting the malware file often insufficient?", options:["Malware frequently installs persistence mechanisms and extra components that must also be removed","Deleting the file automatically reboots every affected server in the enterprise all at once in this case","Antivirus vendors legally prohibit deleting sample files during any active investigation","Deleting the file restores all encrypted data to its original unencrypted readable state"], correct:0, explanation:"Persistence and dropped components remain after deleting one file; the claim it restores encrypted data is wrong." },
  { id:80538, domain:3, level:2, question:"What is the recommended approach when a system is deeply compromised by a rootkit?", options:["Run a single antivirus scan and trust that it fully removed the deeply embedded rootkit code in this case","Rebuild the system from trusted media, since rootkits can hide from tools running on the host","Leave the system online and simply monitor it, assuming the rootkit will remove itself later","Rename the malicious kernel driver so the rootkit can no longer locate its own components"], correct:1, explanation:"Rebuilding from trusted media is safest because rootkits subvert on-host tools; a single AV scan is wrong as it may be deceived." },
  { id:80539, domain:3, level:2, question:"What should occur during the recovery phase after a malware infection is eradicated?", options:["Beginning static and dynamic analysis of the malware sample for the very first time right now","Immediately deleting all incident documentation to reduce storage and reporting overhead","Restoring systems to normal operation and monitoring closely to confirm the threat is gone","Reconnecting infected hosts to the network before any cleanup or validation has been done"], correct:2, explanation:"Recovery restores and monitors validated systems; reconnecting hosts before cleanup is wrong because it risks reinfection." },
  { id:80540, domain:3, level:2, question:"Why is monitoring important immediately after restoring systems from a malware incident?", options:["It is only a compliance formality and has no real value in confirming that the threat is gone","It guarantees that no new, unrelated malware can ever infect the environment again in future","It replaces the need to apply patches to the vulnerability that allowed the original infection in this case","It helps detect any reinfection or residual malicious activity that survived the cleanup effort"], correct:3, explanation:"Post-recovery monitoring catches reinfection and residual activity; claiming it replaces patching is wrong because both are needed." },
  { id:80541, domain:3, level:2, question:"Which control most directly prevents unauthorized executables from running on endpoints?", options:["Application whitelisting, which permits only explicitly approved programs to execute on a host","A weekly full-disk backup routine, which copies data but does not restrict program execution in this case","A guest wireless network, which segments visitors but does not control endpoint executables","An email autoresponder, which acknowledges messages but has no effect on running programs"], correct:0, explanation:"Application whitelisting restricts execution to approved programs; backups are wrong because they protect data, not execution control." },
  { id:80542, domain:3, level:2, question:"How does Endpoint Detection and Response (EDR) help during malware incidents?", options:["It replaces the need for network firewalls by blocking all inbound and outbound traffic itself","It provides continuous endpoint monitoring, threat detection, and response and isolation features","It only stores backup copies of user documents for recovery after a ransomware infection occurs in this case","It exclusively scans email attachments at the gateway and performs no endpoint-level functions"], correct:1, explanation:"EDR delivers continuous endpoint visibility and response; saying it only does backups or email scanning misstates its purpose." },
  { id:80543, domain:3, level:2, question:"Which practice reduces the risk of macro-based malware in office documents?", options:["Enabling all macros automatically so documents open faster for every user in the company","Sharing documents exclusively through email so macros are stripped during transmission","Disabling macros by default and only enabling them for trusted, verified document sources","Storing all documents on removable USB drives to keep macros away from the corporate network"], correct:2, explanation:"Disabling macros by default blocks the common vector; auto-enabling all macros is wrong because it maximizes exposure." },
  { id:80544, domain:3, level:2, question:"What is the value of maintaining an incident response toolkit before malware incidents occur?", options:["It removes the need to ever isolate or contain infected systems during any active incident","It automatically negotiates ransom payments with the attackers on the organization's behalf in this case","It guarantees that no malware can ever bypass the organization's perimeter defenses again","It ensures forensic and analysis tools are ready so responders can act quickly and effectively"], correct:3, explanation:"A prepared toolkit speeds response; claiming it removes the need for containment is wrong because containment is still required." },
  { id:80545, domain:3, level:2, question:"Which log source is most useful for identifying malware command-and-control traffic?", options:["DNS and proxy logs, which can reveal connections to known malicious domains and beacons","Printer usage logs, which record page counts but rarely reveal network beaconing behavior","HVAC facility logs, which track building temperature and have no bearing on network traffic","Physical badge-access logs, which record door entries but not any network-level communications"], correct:0, explanation:"DNS/proxy logs expose C2 domains and beaconing; printer logs are wrong because page counts do not reveal malware communications." },
  { id:80546, domain:3, level:2, question:"What is a logic bomb?", options:["A network appliance that automatically blocks all malware before it reaches any endpoint","Malicious code that lies dormant until a specific condition or trigger causes it to activate","A backup process that detonates redundant copies of files across geographically separate sites","A benign script that only records system performance metrics for later capacity planning use"], correct:1, explanation:"A logic bomb triggers on a condition or date; the network-appliance option is wrong because a logic bomb is malicious code, not defense." },
  { id:80547, domain:3, level:2, question:"Which statement about worms versus viruses is correct?", options:["Viruses spread automatically over networks, while worms always need a user to run a file first","Both worms and viruses are entirely incapable of replicating themselves in any circumstance","Worms can self-propagate across networks, while viruses require a host file and a user action","Worms and viruses are only ever spread through physical USB drives and never over networks"], correct:2, explanation:"Worms self-propagate; viruses need a host and user action. Saying viruses spread automatically reverses the two definitions." },
  { id:80548, domain:3, level:2, question:"What is the main risk of reconnecting an infected host to the network too early?", options:["The host will lose all of its locally stored data as soon as the network cable is plugged back in","Network reconnection permanently disables the host's antivirus and endpoint protection agents","The infected host will automatically clean itself once it regains its network connectivity again","The malware may resume spreading to other systems or re-establish command-and-control links"], correct:3, explanation:"Early reconnection lets malware spread or re-contact C2; the self-cleaning claim is wrong because reconnection does not remove malware." },
  { id:80549, domain:3, level:2, question:"Which of the following is a strong indicator of a botnet infection on a host?", options:["The host regularly beacons to an external command-and-control server at fixed timed intervals","The host receives scheduled operating system updates from the internal patch management server","The host mounts an approved network share during the user's normal daily workflow tasks today","The host synchronizes its clock with the organization's trusted internal NTP time source only"], correct:0, explanation:"Regular beaconing to external C2 signals a bot; scheduled internal patching is wrong because it is expected, legitimate behavior." },
  { id:80550, domain:3, level:2, question:"Why is network segmentation valuable during a malware outbreak?", options:["It automatically removes malware from every host located within the affected network segment","It confines malware to a limited network zone, slowing lateral movement to other segments","It guarantees that no phishing email can ever reach any user inside the organization again","It eliminates the need to isolate individual infected hosts during the containment phase"], correct:1, explanation:"Segmentation limits lateral movement; claiming it removes malware from hosts is wrong because it contains, not cleans, infections." },
  { id:80551, domain:3, level:2, question:"What is the purpose of collecting a malware sample during incident handling?", options:["To immediately release the sample publicly so all competitors receive the same warning fast","To execute it on production servers and measure the real financial damage it can cause today","To analyze it for capabilities and IOCs that inform detection, containment, and eradication","To satisfy a legal requirement that mandates deleting all evidence within one hour of capture"], correct:2, explanation:"Samples are collected to derive IOCs and understand capabilities; running it on production is wrong because that causes real harm." },
  { id:80552, domain:3, level:2, question:"Which hardening measure most directly reduces the attack surface for malware?", options:["Granting all users local administrator rights so they can resolve their own issues quickly","Disabling logging on endpoints to reduce noise and simplify the monitoring dashboards used","Allowing all inbound network traffic by default to avoid disrupting business applications","Removing unnecessary services, software, and open ports from systems to limit exploitation"], correct:3, explanation:"Removing unneeded services and ports shrinks the attack surface; granting everyone admin rights is wrong because it increases risk." },
  { id:80553, domain:3, level:2, question:"What is the role of threat intelligence in handling malware incidents?", options:["It supplies known IOCs and attacker techniques that help detect and attribute the malware","It automatically pays any ransom demand using a shared industry fund set aside for victims","It replaces the need for endpoint protection because it blocks malware before it is created","It guarantees complete immunity from all future infections once it has been subscribed to"], correct:0, explanation:"Threat intelligence provides IOCs and TTPs to aid detection; the ransom-fund claim is wrong and not a function of intelligence." },
  { id:80554, domain:3, level:2, question:"Why should incident responders document actions taken during a malware incident?", options:["To ensure the malware author receives credit for the technique used in the observed attack","To maintain an accurate timeline for analysis, reporting, and evidentiary chain of custody","To replace the need for any technical containment or eradication activity during the response","To guarantee that regulators will waive all penalties associated with the reported breach"], correct:1, explanation:"Documentation supports timeline, reporting, and chain of custody; crediting the author is wrong because it serves no legitimate purpose." },
  { id:80555, domain:3, level:2, question:"What is application whitelisting most effective at stopping?", options:["Inbound phishing emails, which are blocked before they ever reach any user's email inbox","Physical theft of laptops, which whitelisting policies prevent through hardware locking","Execution of unapproved or unknown binaries, including many malware payloads, on endpoints","Distributed denial-of-service floods aimed at the organization's public-facing web servers"], correct:2, explanation:"Whitelisting blocks unapproved execution including malware; stopping phishing email is wrong because that is an email gateway function." },
  { id:80556, domain:3, level:2, question:"Which measure helps prevent malware from spreading via removable USB media?", options:["Encrypting all outbound email attachments so USB drives cannot be read by any other computer in this case","Increasing the display resolution on endpoints so users can better see USB device warnings","Requiring longer Wi-Fi passwords, which prevents USB-borne malware from executing on hosts","Disabling autorun and restricting or scanning USB device usage through endpoint policy controls"], correct:3, explanation:"Disabling autorun and controlling USB usage curbs USB-borne malware; longer Wi-Fi passwords are wrong because they are unrelated to USB media." },
  { id:80557, domain:3, level:2, question:"What is the benefit of using least privilege to limit malware impact?", options:["Malware running under a limited account cannot easily install system-wide or access all data","Least privilege automatically encrypts all user files so ransomware cannot lock them at all in this case","Least privilege guarantees that phishing emails will never be delivered to any inbox again","Least privilege makes antivirus signatures unnecessary because malware simply cannot run"], correct:0, explanation:"Least privilege limits what malware can do under a low-rights account; the auto-encrypt claim is wrong and not a privilege function." },
  { id:80558, domain:3, level:2, question:"Which action is part of preparing for malware incidents rather than responding to them?", options:["Isolating an infected host from the network after a malware alert has already been triggered in this case","Establishing an incident response plan, playbooks, and trained personnel ahead of any incident","Restoring encrypted files from backups after a ransomware attack has been fully eradicated","Analyzing a captured malware sample in a sandbox during the active investigation of a breach"], correct:1, explanation:"Building plans, playbooks, and trained staff is preparation; isolating a host after an alert is wrong because it is a response activity." },
  { id:80559, domain:3, level:2, question:"What does behavioral (anomaly) detection add over signature-based malware detection?", options:["It only detects malware whose exact signature already exists in the antivirus definition database in this case","It removes the need to ever update any detection tooling because behavior never changes at all","It can flag previously unknown malware by identifying suspicious activity rather than known hashes","It works solely by matching file names against a fixed static list of banned program titles"], correct:2, explanation:"Behavioral detection flags unknown threats by activity; the signature-only description is wrong because that is exactly what it improves upon." },
  { id:80560, domain:3, level:2, question:"Why is patching important in preventing malware infections?", options:["It automatically decrypts any files that ransomware may have already locked on the endpoint","It removes the need for backups because patched systems can never be infected by malware","It negotiates directly with attackers to have infected systems released without any payment","It closes known vulnerabilities that malware and exploit kits commonly use to gain access"], correct:3, explanation:"Patching removes vulnerabilities exploited by malware; the auto-decrypt claim is wrong because patching cannot recover encrypted data." },
  { id:80561, domain:3, level:2, question:"Which of the following best describes a Trojan horse's method of compromise?", options:["It relies on tricking a user into running it by masquerading as a legitimate, desirable program","It exploits a network service automatically and spreads to other hosts without any user action","It encrypts every file it touches immediately and always leaves a visible ransom demand note","It only infects the master boot record and never presents itself as a useful application at all"], correct:0, explanation:"Trojans depend on user execution via disguise; the automatic network-spread option is wrong because that describes a worm, not a trojan." },
  { id:80562, domain:3, level:2, question:"What is the primary purpose of isolating an infected host during containment?", options:["To immediately erase all data on the host so the malware has nothing left to encrypt or steal","To prevent the malware from spreading or communicating while preserving it for investigation","To provide the attacker with a controlled demonstration environment for their malware sample","To improve the host's performance so users can continue working during the active incident"], correct:1, explanation:"Isolation stops spread and C2 while preserving evidence; erasing all data is wrong because it destroys the evidence needed for analysis." },
  { id:80563, domain:3, level:2, question:"Which of these is a legitimate reason NOT to pay a ransomware demand?", options:["Payment is always cheaper than restoring from backups, so it is never a financial consideration","Paying instantly removes the malware from every affected host across the entire organization","Payment funds criminal operations and gives no assurance that a working key will be provided","Paying is legally required in every jurisdiction once ransomware encryption has been detected"], correct:2, explanation:"Payment funds crime and does not guarantee recovery; the 'legally required' claim is wrong because no such universal law exists." },
  { id:80564, domain:3, level:2, question:"How can an organization detect ransomware early through behavioral monitoring?", options:["By waiting for users to report that all of their files now have a strange new file extension in this case","By counting the number of advertisements displayed in each user's web browser every hour","By checking only whether the antivirus definitions were updated on the last maintenance day","By alerting on rapid mass file modifications and unusual encryption-like activity across shares"], correct:3, explanation:"Rapid mass file changes signal ransomware behaviorally; waiting for user reports is wrong because it detects the attack far too late." },
  { id:80565, domain:3, level:2, question:"What is the value of maintaining IOCs from a malware incident for future use?", options:["They enable faster detection and blocking of the same or related threats in later incidents","They permanently prevent the same malware author from ever writing new malware families again","They replace the need for any endpoint or network monitoring across the whole environment","They automatically remediate every infected host the moment the incident report is finalized"], correct:0, explanation:"Retained IOCs speed future detection and blocking; the author-prevention claim is wrong because IOCs cannot stop malware from being written." },
  { id:80566, domain:3, level:2, question:"Which step should follow identifying that multiple hosts share the same malware IOCs?", options:["Immediately closing the incident because shared IOCs prove the infection is already contained","Scoping the incident to find all affected hosts, then containing them to stop further spread","Ignoring the additional hosts and remediating only the single machine first reported by a user","Deleting the shared IOCs so responders are not distracted by duplicate detection information"], correct:1, explanation:"Shared IOCs mean the incident should be scoped and all hosts contained; ignoring additional hosts is wrong because the infection is broader." },
  { id:80567, domain:3, level:3, question:"An analyst sees a legitimate process like powershell.exe spawning encoded commands and contacting an external IP. This most likely indicates what?", options:["A routine software update, since PowerShell is a signed Microsoft binary and always trusted","A hardware fault causing the process to randomly generate encoded network traffic on its own","Fileless malware abusing a living-off-the-land binary to execute in memory and reach C2","A backup job, because backup software commonly issues encoded PowerShell to external servers"], correct:2, explanation:"Encoded PowerShell beaconing externally signals fileless/LOLBin abuse; trusting it as a routine update ignores the malicious behavior." },
  { id:80568, domain:3, level:3, question:"A responder must contain ransomware spreading via SMB across a subnet. Which action best limits lateral movement quickly?", options:["Emailing all users to ask them to stop opening documents until the incident is fully resolved in this case","Waiting for the next scheduled antivirus signature update before taking any network action","Increasing the ransom-negotiation budget so the business can recover files more quickly later","Blocking SMB traffic between hosts and isolating the affected subnet at the switch or firewall"], correct:3, explanation:"Blocking SMB and isolating the subnet halts the spread vector; emailing users is wrong because it is too slow to stop active propagation." },
  { id:80569, domain:3, level:3, question:"After eradicating malware, users report the infection returned within hours. What is the most likely cause?", options:["A persistence mechanism or unpatched entry vector was missed, allowing the malware to return","Antivirus signatures are too new, which causes previously cleaned malware to reappear on hosts","The recovery phase was performed correctly, which is precisely what caused the malware to return","Network monitoring alerts always cause dormant malware to reactivate on the restored systems"], correct:0, explanation:"Rapid reinfection points to missed persistence or an open vector; blaming correct recovery or monitoring is wrong as neither reintroduces malware." },
  { id:80570, domain:3, level:3, question:"An organization wants to detect fileless malware that leaves few disk artifacts. Which capability is most effective?", options:["Signature-only file scanning of the disk, which reliably flags all in-memory-only threats too in this case","Behavioral and memory-based monitoring via EDR that inspects process activity and in-memory code","A stronger spam filter alone, which fully prevents any fileless technique from ever executing","Longer, more complex user passwords, which stop in-memory malware from running on a host"], correct:1, explanation:"Behavioral/memory monitoring detects fileless activity; signature-only disk scanning is wrong because fileless malware leaves little on disk." },
  { id:80571, domain:3, level:3, question:"A malware sample checks system uptime, mouse movement, and installed tools before running. Why?", options:["It is optimizing performance by measuring the host's available hardware before doing real work","It is verifying the user's license compliance before enabling its legitimate documented features","It is performing anti-sandbox checks to avoid executing inside an automated analysis environment","It is generating a friendly diagnostic report to help administrators tune the affected system"], correct:2, explanation:"These are anti-analysis/sandbox evasion checks; calling them performance tuning or licensing misreads clearly evasive behavior." },
  { id:80572, domain:3, level:3, question:"During dynamic analysis, malware makes no network calls and appears inert. What is a likely explanation?", options:["Malware never makes network connections, so silence always confirms the sample is fully benign","Dynamic analysis cannot observe network activity, so no calls will ever be seen in any case at all","The sample must have already fully removed itself from the analysis machine before executing","The malware may be sandbox-aware or awaiting a trigger, or the C2 server is currently offline"], correct:3, explanation:"Inertness can mean evasion, a dormant trigger, or dead C2; claiming malware never uses the network is wrong and misleading." },
  { id:80573, domain:3, level:3, question:"A host shows sustained high CPU usage and connections to a mining pool domain. Which malware is most likely present?", options:["A cryptomining trojan (cryptojacker) using host resources to mine cryptocurrency for the attacker","Ransomware, which would instead encrypt files rather than sustain connections to a mining pool","A keylogger, whose activity is silent and would not generate sustained mining-pool connections","Adware, which shows advertisements and does not typically connect to cryptocurrency mining pools in this case"], correct:0, explanation:"Mining-pool connections plus high CPU indicate cryptojacking; ransomware is wrong because it encrypts files rather than mining coins." },
  { id:80574, domain:3, level:3, question:"An incident handler must preserve evidence on an infected host before eradication. What is the correct order of volatility?", options:["Wipe the disk first, then attempt to recover deleted memory contents from the erased drive later","Capture volatile memory and network state first, then acquire disk images before remediation","Patch the operating system first, which conveniently preserves all volatile evidence intact","Reboot the host first to refresh its state, then capture the now-cleaner memory contents"], correct:1, explanation:"Volatile data (RAM, network state) is collected before disk per order of volatility; rebooting first is wrong because it destroys memory evidence." },
  { id:80575, domain:3, level:3, question:"A phishing document downloads a payload only when opened on a domain-joined PC. This behavior indicates what?", options:["A benign template, since documents cannot download payloads based on domain membership at all","A hardware defect that causes random downloads whenever the document is opened anywhere at all","A targeted dropper using environmental checks to activate only on intended enterprise hosts","A standard Windows update mechanism that legitimately delivers payloads through documents"], correct:2, explanation:"Environment-aware activation marks a targeted dropper; claiming documents cannot do this is wrong because malicious macros can check domain membership." },
  { id:80576, domain:3, level:3, question:"After a ransomware incident, the team finds backups were also encrypted. What preparation gap does this reveal?", options:["Backups were too small, which is why the ransomware was able to encrypt every one of them","Backups ran too frequently, which is the specific reason the ransomware could reach them","Backups used strong encryption themselves, which is what allowed the attacker to lock them","Backups were online and reachable by the ransomware instead of being isolated or immutable"], correct:3, explanation:"Reachable online backups got encrypted, revealing a lack of offline/immutable copies; backup size and frequency are irrelevant to reachability." },
  { id:80577, domain:3, level:3, question:"An EDR alert flags a signed system binary loading an unsigned DLL from a user's temp folder. This pattern most suggests what?", options:["DLL side-loading, where malware places a malicious DLL to be loaded by a trusted signed binary","A normal driver installation, which always loads unsigned DLLs from temporary user directories","A routine antivirus update, which legitimately side-loads DLLs from each user's temp folder daily","A printer spooler refresh, which is the only process permitted to load DLLs from temp folders"], correct:0, explanation:"A trusted binary loading an unsigned DLL from temp is classic side-loading; calling it a normal driver install ignores the suspicious location." },
  { id:80578, domain:3, level:3, question:"To handle a botnet infection across many hosts, which combined action is most effective?", options:["Only reimaging one representative host and assuming all other bots will disconnect on their own","Blocking C2 domains and IPs at the perimeter while isolating and remediating infected hosts","Simply increasing internet bandwidth so the beaconing traffic no longer congests the network","Asking users to reboot their machines daily, which permanently removes any botnet infection"], correct:1, explanation:"Blocking C2 plus isolating/remediating bots addresses both control channel and hosts; reimaging one host is wrong because others stay infected." },
  { id:80579, domain:3, level:3, question:"A responder wants to confirm whether a suspicious binary is known malware without executing it. What is the fastest safe method?", options:["Double-click the binary on a production server to see whether antivirus raises any alert first","Rename the file to a .txt extension, which safely neutralizes and identifies the malware itself","Compute its hash and check it against threat-intelligence and antivirus reputation databases","Email the binary to all staff and ask whether anyone recognizes the program by its icon alone"], correct:2, explanation:"Hashing and checking reputation is fast and safe with no execution; double-clicking it on production is wrong because it risks infection." },
  { id:80580, domain:3, level:3, question:"A malware incident report should primarily help the organization do what after the incident?", options:["Assign personal blame to the individual user who first clicked the malicious phishing link today","Guarantee that the exact same malware family can never be developed by any attacker ever again","Replace the need for future preparation, monitoring, detection, and containment activities","Improve defenses and processes through documented lessons learned and concrete recommendations"], correct:3, explanation:"Reports drive lessons-learned improvements; assigning personal blame is wrong because it undermines a constructive, blame-free response culture." },
  { id:80581, domain:3, level:3, question:"Which scenario best illustrates the need for user-awareness training as a malware countermeasure?", options:["Employees repeatedly open phishing attachments that deliver malware despite technical controls","A firewall correctly blocks inbound scans, showing that training would have no added value here","Automated patching closes vulnerabilities, proving human behavior is irrelevant to infections","EDR isolates an infected host automatically, demonstrating that awareness efforts are wasteful"], correct:0, explanation:"Repeated attachment-opening shows the human vector training addresses; the firewall example is wrong because it does not involve user behavior." },
  { id:80582, domain:3, level:3, question:"An attacker distributes a trojanized software installer on a download site. Which countermeasure most directly mitigates this?", options:["Increasing the monitor brightness so users can more clearly read the installer's dialog boxes","Verifying installer integrity with vendor checksums or signatures before executing downloads","Disabling the corporate email system so no download links can ever reach any employee inbox","Allowing every downloaded installer to run with administrative rights to speed installation"], correct:1, explanation:"Checksum/signature verification detects tampered installers; allowing all installers admin rights is wrong because it worsens the risk." },
  { id:80583, domain:3, level:3, question:"A ransomware note claims files are encrypted with a unique attacker-held key. Before considering recovery, the handler should first do what?", options:["Reboot all affected machines several times to interrupt the attacker's remote encryption process","Immediately format every affected drive to guarantee the ransomware is completely eliminated","Isolate affected systems and identify the ransomware variant to check for known free decryptors","Transfer the ransom amount to a holding account so payment can be made without any delay later"], correct:2, explanation:"Isolating and identifying the variant enables checking for free decryptors; formatting drives first is wrong because it destroys recoverable data." },
  { id:80584, domain:3, level:3, question:"The same malware appears on hosts across three departments within minutes. What does this pattern most strongly suggest?", options:["Three unrelated coincidental infections that happened to occur at the same time by pure chance in this case","A false positive, because real malware can never appear on multiple hosts within a few minutes","Normal software deployment, since IT always pushes identical unknown binaries to many hosts","Automated worm-like propagation or a shared infection vector spreading rapidly across the network"], correct:3, explanation:"Rapid multi-host appearance indicates worm-like spread or a shared vector; calling it pure coincidence ignores the correlated timing." },
  { id:80585, domain:3, level:3, question:"When choosing between reimaging and cleaning a malware-infected host, reimaging is generally preferred when what is true?", options:["The infection is deep or uncertain, such as rootkits, making complete manual cleanup unreliable","The host contains no sensitive data, so cleaning is always guaranteed to be perfectly effective","The malware is simple adware, which can never be removed by reimaging the affected system","The organization lacks any backups, so reimaging is the only option regardless of the situation"], correct:0, explanation:"Reimaging is preferred when cleanup is unreliable, like deep rootkits; claiming cleaning is always effective is wrong for stealthy infections." },
  { id:80586, domain:3, level:3, question:"A handler observes an infected host making DNS queries for many random-looking domains. This most likely indicates what?", options:["A misconfigured browser that randomly mistypes domain names during normal user web browsing in this case","A domain generation algorithm (DGA) used by malware to locate its command-and-control server","A legitimate DNS load-balancing feature that intentionally rotates through random hostnames","A hardware network card defect that corrupts domain names as they leave the infected host"], correct:1, explanation:"Many random-domain lookups indicate a DGA locating C2; the browser-mistype option is wrong because it cannot produce that systematic pattern." },
  { id:80587, domain:3, level:3, question:"A workstation's antivirus was disabled without user action, and unknown scheduled tasks appeared. What should the handler suspect?", options:["A routine Windows feature that always disables antivirus and creates tasks during normal updates in this case","A power-saving setting that legitimately turns off antivirus to extend the laptop battery life","Active malware that disabled defenses and established persistence to survive on the compromised host","A user preference change that safely disables antivirus while adding harmless scheduled tasks"], correct:2, explanation:"Disabled AV plus new tasks points to active malware establishing persistence; the 'routine update' claim is wrong because updates do not disable AV." },
  { id:80588, domain:3, level:3, question:"During eradication, the team wants to ensure the same vulnerability is not reused. What must they include?", options:["Deleting all system logs so future auditors cannot see how the malware initially got into the host","Reconnecting the host to the network right away so business operations can resume more quickly","Leaving the vulnerable service running but renaming it so the malware cannot find it next time","Patching or reconfiguring the exploited weakness that allowed the malware to gain initial access"], correct:3, explanation:"Closing the exploited weakness prevents reuse; deleting logs is wrong because it destroys evidence and does not fix the underlying vulnerability." },
  { id:80589, domain:3, level:3, question:"An organization detected malware spreading through a compromised software update mechanism. This is best described as what?", options:["A supply-chain attack, where trusted update infrastructure is abused to distribute malware widely","A brute-force attack, where the attacker guesses credentials to log in to each host individually in this case","A denial-of-service attack, which floods the update server to make it unavailable to all clients","A physical attack, which requires the attacker to be present at each machine to install malware"], correct:0, explanation:"Abusing a trusted update channel is a supply-chain attack; brute force is wrong because no credential guessing is involved in this scenario." },
  { id:80590, domain:3, level:3, question:"A responder finds that isolating one infected host did not stop the spread. What is the most likely reason?", options:["Isolating a host always accelerates malware spread, so isolation should never be used at all","Additional infected hosts or a shared vector are also propagating the malware across the network","The malware physically jumped between machines without using any network connection whatsoever","The single isolated host was actually the only infected system in the entire environment already"], correct:1, explanation:"Continued spread implies other infected hosts or a shared vector; the 'isolation accelerates spread' claim is wrong and contradicts containment practice." },
  { id:80591, domain:3, level:3, question:"A malware sample is heavily packed and obfuscated, resisting static analysis. What is the best next step?", options:["Conclude the file is benign because packed samples can never be analyzed by any available method","Delete the sample immediately so it cannot consume any further analyst time or storage space","Perform dynamic analysis in a sandbox to observe its runtime behavior since static reading is limited","Run the packed sample directly on a production host to reveal its behavior in a realistic setting in this case"], correct:2, explanation:"Dynamic analysis reveals behavior when static is blocked by packing; running it on production is wrong because that risks a real infection." },
  { id:80592, domain:3, level:3, question:"After a ransomware attack, executives ask whether decrypting files is possible without paying. What should the handler check first?", options:["Whether increasing the office internet speed will make the encrypted files open more quickly again","Whether renaming the ransom note file will automatically restore access to the encrypted data","Whether the attacker's payment page accepts a discount code to reduce the total ransom amount","Whether the specific ransomware variant has a publicly available free decryptor or key weakness"], correct:3, explanation:"Checking for a known free decryptor or key weakness is the right first step; renaming the note is wrong because it has no effect on encryption." },
  { id:80593, domain:3, level:3, question:"An incident reveals that a low-privileged user's infection did not spread system-wide. Which control most likely helped?", options:["Least-privilege access, which limited what the malware could do under the restricted user account","A brighter monitor, which helped the user notice the malware warning message on their screen","A faster CPU, which processed the malware more quickly and thereby prevented it from spreading","A larger hard drive, which gave the malware so much space that it never needed to spread at all in this case"], correct:0, explanation:"Least privilege confined the malware's impact; the faster-CPU claim is wrong because processing speed does not limit malware capability." },
  { id:80594, domain:3, level:3, question:"A handler must decide the containment strategy for critical servers infected with malware. What is the key trade-off?", options:["Choosing whichever server has the newest hardware regardless of its role or business importance in this case","Balancing the need to stop malware spread against maintaining essential business service availability","Deciding the exact font used in the incident report before any technical containment can begin","Selecting the ransom payment currency in advance so recovery is not delayed by a later decision"], correct:1, explanation:"Containment for critical servers balances spread control against availability; the font-choice option is wrong and irrelevant to containment." },
  { id:80595, domain:3, level:3, question:"Post-incident, the team notes the malware entered through an unpatched internet-facing service. What lesson should be captured?", options:["Abandon all internet-facing services permanently since any exposed service is impossible to secure","Assume the same service can never be exploited again now that this one incident has been resolved","Strengthen vulnerability and patch management for exposed services to prevent similar future intrusions","Rely solely on paying future ransoms rather than investing in any preventive security controls at all in this case"], correct:2, explanation:"The lesson is to improve patch management for exposed services; abandoning all such services is wrong because it is impractical and unnecessary." },
  { id:80596, domain:3, level:3, question:"An analyst observes malware injecting code into a legitimate running process. This technique is used primarily to do what?", options:["Improve the legitimate application's performance by sharing its optimized memory and code paths","Automatically alert the security team that a suspicious process injection has just taken place","Permanently repair any corruption in the legitimate process so the application runs more reliably in this case","Evade detection and inherit the trust and privileges of the legitimate host process it injects into"], correct:3, explanation:"Process injection hides malware in a trusted process and borrows its privileges; the performance-boost claim is wrong and misrepresents the intent." },
  { id:80597, domain:3, level:3, question:"A network shows a single host connecting outbound to hundreds of internal hosts on port 445. What activity does this most likely represent?", options:["Malware performing lateral movement or worm-like scanning and spreading over SMB internally","A normal print job being sent from one workstation to a single nearby office network printer","A routine software license check that contacts one vendor server on the public internet once","A backup client copying a user's documents to one designated internal file server as scheduled"], correct:0, explanation:"Fan-out to many hosts on 445 indicates SMB lateral movement or worm spread; a single print job is wrong because it does not touch hundreds of hosts." },
  { id:80598, domain:3, level:3, question:"During recovery, the team must decide when to reconnect cleaned systems to the network. What condition should be met first?", options:["Confirmation that the ransom has been paid so the attacker permits systems to rejoin the network","Verification that the malware and its persistence are fully removed and the entry vector is closed","Assurance that every user has changed their desktop wallpaper to signal the incident is over now","A guarantee from the antivirus vendor that no new malware will ever be written in the future again"], correct:1, explanation:"Systems should rejoin only after verified cleanup and closed entry vector; paying ransom is wrong because it is unnecessary and does not clean systems." },
  { id:80599, domain:3, level:3, question:"A forensic examiner needs to determine what a captured trojan did on a host. Which combination is most informative?", options:["Reading only the file's name and icon, which fully reveal every action the trojan performed on the host","Checking solely the file's creation date, which alone explains the trojan's complete functionality","Correlating dynamic sandbox behavior with host artifacts like registry, logs, and network captures","Counting how many times the user clicked the mouse while the trojan was running on the machine"], correct:2, explanation:"Combining dynamic behavior with host artifacts gives the fullest picture; reading only name and icon is wrong because those reveal nothing about behavior." },
  { id:80600, domain:3, level:3, question:"An organization wants to reduce the blast radius if a single endpoint is infected by malware. Which architectural control helps most?", options:["A single flat network where every host can freely reach every other host without restrictions","Granting all endpoints shared administrator credentials so support staff can fix issues faster","Disabling all logging enterprise-wide so infected hosts generate less noise during an incident","Network segmentation and micro-segmentation that restrict lateral movement between host groups"], correct:3, explanation:"Segmentation limits lateral movement and blast radius; a flat network is wrong because it lets malware reach every host without any restriction." },
  { id:80601, domain:3, level:3, question:"A ransomware operator also threatens to leak stolen data unless paid. This tactic is known as what?", options:["Double extortion, combining file encryption with the threat of publishing exfiltrated data","Single-factor extortion, which only ever involves locking files and never any data theft at all","A denial-of-service attack, which floods the network rather than encrypting or stealing any data","A watering-hole attack, which compromises a website that the target organization commonly visits"], correct:0, explanation:"Encryption plus a data-leak threat is double extortion; a denial-of-service label is wrong because no traffic flooding is involved in this tactic." },
  { id:80602, domain:3, level:3, question:"A handler needs to gather IOCs to hunt for a malware family across the estate. Which set is most useful for detection?", options:["The physical color of the affected laptops and the brand of keyboard attached to each of the hosts in this case","File hashes, malicious domains and IPs, registry keys, and distinctive process or network behaviors","The names of the employees who were on vacation during the week the incident was first detected","The office building floor numbers where the infected machines happen to be physically located"], correct:1, explanation:"Hashes, domains, IPs, keys, and behaviors are actionable IOCs; laptop color is wrong because it has no bearing on detecting malware." },
  { id:80603, domain:3, level:1, question:"Which malware category specifically targets and infects the boot sector of a storage device?", options:["An email worm, which spreads through mass mailing rather than infecting any disk boot record","A browser hijacker, which changes browser settings but does not touch the disk boot sector","A boot sector virus, which infects the boot record and loads before the operating system starts","A password stealer, which harvests stored credentials rather than infecting a boot record area in this case"], correct:2, explanation:"Boot sector viruses infect the boot record and load early; an email worm is wrong because it spreads via mail, not by boot infection." },
  { id:80604, domain:3, level:1, question:"What is a browser hijacker?", options:["A firewall module that legitimately blocks malicious web pages before they can load in a browser","A signed browser extension published by the vendor to improve the built-in privacy protections","A backup tool that safely exports browser bookmarks to protect them from any malware infection","Malware that alters browser settings such as the home page or search engine without consent"], correct:3, explanation:"A browser hijacker changes browser settings without consent; the firewall-module option is wrong because it is a protective feature, not malware." },
  { id:80605, domain:3, level:1, question:"What is scareware?", options:["Malware that uses fake alerts to frighten users into buying or installing bogus security software","A legitimate antivirus product that scans the system quietly without displaying any alerts at all","A backup utility that warns users before it overwrites their existing files during a restore job","A patch that fixes a known scare-related vulnerability in the operating system's update service"], correct:0, explanation:"Scareware uses fake alarms to trick users into paying for bogus software; a legitimate antivirus is wrong because it is genuine, not deceptive." },
  { id:80606, domain:3, level:1, question:"Which malware term describes a self-contained program that copies itself to spread automatically?", options:["A patch, a vendor-provided update that fixes vulnerabilities rather than replicating itself at all","A worm, a standalone program that replicates and spreads across systems without a host file","A cookie, a small text file a website stores in the browser to remember a user's session state","A driver, low-level software that lets the operating system communicate with hardware devices"], correct:1, explanation:"A worm is a standalone self-replicating program; a patch is wrong because it is a legitimate fix and does not copy or spread itself." },
  { id:80607, domain:3, level:1, question:"What is the payload of a piece of malware?", options:["The digital certificate that proves the malware was signed by a trusted software publisher","The user manual that attackers ship alongside the malware to explain its documented features","The component that carries out the malware's actual malicious action once it is activated","The antivirus signature that vendors create to detect and quarantine the malware sample later"], correct:2, explanation:"The payload performs the malicious action; a digital certificate is wrong because it is unrelated to what harmful action the malware executes." },
  { id:80608, domain:3, level:1, question:"Which malware type is designed to mine cryptocurrency using a victim's computing resources?", options:["A ransomware strain, which instead encrypts files and demands a payment for their decryption","A rootkit, whose primary purpose is concealment rather than generating cryptocurrency revenue","A keylogger, which captures typed keystrokes rather than consuming resources to mine coins","A cryptojacker, which hijacks CPU or GPU resources to mine cryptocurrency for the attacker"], correct:3, explanation:"A cryptojacker mines coins using stolen compute; ransomware is wrong because it extorts via encryption rather than mining cryptocurrency." },
  { id:80609, domain:3, level:1, question:"What is a backdoor in the context of malware?", options:["A hidden method that lets an attacker bypass normal authentication to access a system later","A front-facing login page that securely authenticates legitimate users before granting access","A backup channel used only by administrators to restore data after a confirmed hardware failure","A logging feature that records every successful and failed login attempt for later auditing use"], correct:0, explanation:"A backdoor bypasses authentication for covert access; a legitimate login page is wrong because it enforces, rather than bypasses, authentication." },
  { id:80610, domain:3, level:1, question:"Which of the following describes a polymorphic virus?", options:["A virus that always keeps exactly the same byte pattern so it is easy to detect every time","A virus that changes its code or appearance on each infection to evade signature detection","A virus that only infects printers and other peripherals rather than the host computer itself","A virus that can never replicate and simply displays a static message on the infected screen"], correct:1, explanation:"Polymorphic viruses mutate to evade signatures; the fixed-byte-pattern option is wrong because that is precisely the opposite of polymorphism." },
  { id:80611, domain:3, level:1, question:"What is spear phishing as a malware delivery technique?", options:["A broad untargeted spam campaign sent identically to millions of random recipients at once","A physical attack requiring the attacker to insert a USB drive into the victim's machine directly","A targeted phishing attack tailored to a specific individual or organization to deliver malware","A denial-of-service technique that overwhelms a mail server so it cannot deliver any messages"], correct:2, explanation:"Spear phishing is targeted and tailored to the victim; the broad untargeted spam option is wrong because it lacks the targeted nature of spear phishing." },
  { id:80612, domain:3, level:1, question:"What is a RAT most commonly used for by an attacker after infection?", options:["Automatically installing all pending operating system patches to keep the infected host secure","Encrypting the host's files and immediately presenting the user with a visible ransom demand","Displaying pop-up advertisements to generate click revenue from the compromised user's browser","Remotely controlling the host to steal data, watch the user, or run further malicious commands"], correct:3, explanation:"A RAT gives remote control for theft and further commands; the auto-patching option is wrong because RATs harm, not secure, the host." },
  { id:80613, domain:3, level:1, question:"Which term describes software that appears legitimate but secretly performs malicious actions?", options:["A trojan, which masquerades as a legitimate program while hiding harmful functionality inside","A hypervisor, which is virtualization software that runs and manages multiple guest machines","A compiler, which translates human-readable source code into an executable machine program","A defragmenter, a maintenance tool that reorganizes files on a disk to improve read performance"], correct:0, explanation:"A trojan hides malice behind a legitimate appearance; a hypervisor is wrong because it is legitimate virtualization software, not disguised malware." },
  { id:80614, domain:3, level:1, question:"What is the primary function of a packer in malware?", options:["To translate the malware into a different human language for attackers in other countries","To compress and obfuscate the malware code so it evades signature-based antivirus detection","To securely archive clean backup copies of files before the malware encrypts the originals in this case","To officially register the malware with a certificate authority for trusted code signing"], correct:1, explanation:"A packer compresses and obfuscates to evade signatures; the language-translation option is wrong because packing has nothing to do with human language." },
  { id:80615, domain:3, level:1, question:"Which term refers to a previously unseen malware variant with no existing antivirus signature?", options:["Legacy malware, which is old and well documented with signatures available in every product","Quarantined malware, which antivirus has already isolated and neutralized on the infected host","Zero-day or unknown malware, which evades signature detection because no signature yet exists","Signed malware, which carries a valid publisher certificate recognized by every operating system"], correct:2, explanation:"Zero-day malware has no existing signature; legacy malware is wrong because it is old and already well-covered by signatures." },
  { id:80616, domain:3, level:1, question:"What is a mass-mailing worm?", options:["A firewall rule that mass-blocks all inbound email so worms cannot enter the organization","A newsletter service that legitimately sends bulk marketing emails to subscribed customers","A spam filter that automatically deletes suspicious bulk email before users can open it up","A worm that spreads by emailing copies of itself to addresses found on infected systems"], correct:3, explanation:"Mass-mailing worms email copies of themselves to harvested addresses; the firewall-rule option is wrong because it is a defense, not a worm." },
  { id:80617, domain:3, level:1, question:"Which malware behavior involves disabling security tools on an infected host?", options:["Defense evasion, where malware terminates or disables antivirus and other security controls","Data backup, where malware safely copies files to protect them before any encryption occurs","Patch management, where malware installs missing security updates to harden the infected host","Log rotation, where malware neatly archives old logs to keep the disk from filling up over time"], correct:0, explanation:"Disabling security tools is defense evasion; the data-backup option is wrong because malware does not protect the victim's files as a backup would." },
  { id:80618, domain:3, level:1, question:"What is an indicator that a file may be a trojan rather than a legitimate application?", options:["It is digitally signed by a well-known vendor and behaves exactly as its documentation describes in this case","It requests unusual permissions or performs hidden network activity unrelated to its stated purpose","It appears in the vendor's official app store with many verified reviews from real customers","It uses only the minimum permissions required and clearly explains each one to the user first"], correct:1, explanation:"Hidden activity unrelated to its stated purpose signals a trojan; a properly signed, well-behaved app is wrong because that indicates legitimacy." },
  { id:80619, domain:3, level:1, question:"What is a bot in the context of a botnet?", options:["The central server the attacker personally uses to type commands into the botnet each day","A security appliance that automatically detects and removes all bots from the local network","An individual compromised host that receives and executes commands from a botnet controller","A helpdesk chatbot that answers user questions about how to remove malware from a computer"], correct:2, explanation:"A bot is a single compromised host under botnet control; the central server is wrong because that is the command-and-control node, not a bot." },
  { id:80620, domain:3, level:1, question:"Which malware type is often spread by tricking users into enabling content in a document?", options:["A boot sector virus, which infects the disk boot record and does not rely on document macros","A network worm, which spreads over the network without any document or user interaction at all","A hardware rootkit, which resides in firmware and is unrelated to enabling document content","A macro virus, which activates when a user enables macros in an infected office document"], correct:3, explanation:"Macro viruses trigger when users enable macros; a network worm is wrong because it spreads over the network without needing a document." },
  { id:80621, domain:3, level:1, question:"What does 'signature-based detection' rely on to identify malware?", options:["Known patterns or hashes of previously identified malware stored in a definitions database","The real-time emotional reaction of the user when a suspicious file first opens on the screen","The physical temperature of the CPU while a suspected malicious process is actively running","The alphabetical order of file names in the folder where the suspected malware is located"], correct:0, explanation:"Signature detection matches known patterns or hashes; the CPU-temperature option is wrong because heat is unrelated to identifying malware code." },
  { id:80622, domain:3, level:1, question:"Which of the following is a hallmark of ransomware once it has finished encrypting files?", options:["The affected files silently repair themselves and return to normal without any user action taken","A ransom note appears with payment instructions and a deadline to obtain the decryption key","The antivirus automatically decrypts the files and removes the ransomware within a few seconds","The system speeds up noticeably because the ransomware frees memory after finishing its work"], correct:1, explanation:"A ransom note with payment instructions is the hallmark; self-repairing files are wrong because ransomware locks data rather than restoring it." },
  { id:80623, domain:3, level:2, question:"Which phase of malware incident handling focuses on identifying that an incident has occurred?", options:["Preparation, which builds capabilities in advance and does not itself identify active incidents","Recovery, which restores affected systems only after the malware has already been removed","Detection and analysis, where alerts, IOCs, and behavior confirm that malware is present","Post-incident activity, which reviews the closed incident rather than identifying a new one"], correct:2, explanation:"Detection and analysis confirms an incident; preparation is wrong because it builds readiness before any incident is identified." },
  { id:80624, domain:3, level:2, question:"What should responders establish first when triaging a suspected malware alert?", options:["Which employee to blame for the alert before performing any technical validation of the event","How large a ransom the organization is willing to pay if the alert turns out to be ransomware","The exact resale value of the affected hardware before deciding whether to investigate at all","Whether the alert is a true positive and the scope and severity of any confirmed infection"], correct:3, explanation:"Triage validates the alert and assesses scope and severity; assigning blame first is wrong because it does not advance the investigation." },
  { id:80625, domain:3, level:2, question:"Why is establishing a chain of custody important when handling malware evidence?", options:["It documents who handled evidence and when, preserving its integrity for legal or internal use","It automatically removes the malware from the evidence so the sample becomes safe to email","It speeds up the encryption process the malware uses so analysts can study it more quickly","It guarantees that the malware author will be prosecuted regardless of any other evidence found"], correct:0, explanation:"Chain of custody preserves evidence integrity and handling records; the auto-removal claim is wrong because documentation does not clean samples." },
  { id:80626, domain:3, level:2, question:"Which containment approach is appropriate when malware is confined to a single non-critical host?", options:["Shutting down the entire enterprise network to be certain the isolated host cannot spread malware","Isolating that host from the network while allowing other business systems to continue operating","Ignoring the host entirely since a single non-critical machine can never affect the organization","Paying a preventive ransom so the malware author agrees not to spread to any other host later"], correct:1, explanation:"Isolating just the affected host preserves operations; shutting down the whole network is wrong because it is disproportionate for one non-critical host." },
  { id:80627, domain:3, level:2, question:"What is a key benefit of having predefined malware playbooks before an incident?", options:["They guarantee that no malware will ever reach any endpoint within the organization again","They eliminate the need to detect or analyze malware because responses are already automated","They give responders consistent, tested steps so they can react quickly and avoid mistakes","They automatically pay ransoms on the organization's behalf without any human approval needed"], correct:2, explanation:"Playbooks provide consistent, tested response steps; the guarantee-of-no-malware claim is wrong because playbooks guide response, not prevention." },
  { id:80628, domain:3, level:2, question:"Which of the following is a network-based indicator of a malware infection?", options:["A user opening an approved internal web application over the organization's trusted intranet","A workstation downloading signed antivirus updates from the vendor's official update servers","A file server responding to authenticated share access requests from a normal domain user","Traffic to a known malicious domain or beaconing at regular intervals to an external server"], correct:3, explanation:"Traffic to malicious domains or beaconing is a network IOC; approved intranet access is wrong because it is expected, benign traffic." },
  { id:80629, domain:3, level:2, question:"Why should responders avoid running unknown malware on their own workstations?", options:["It could infect the responder's system and spread further, and it destroys forensic control","It always improves the workstation's performance, which biases the later analysis results","It is the only reliable way to compute a file's hash for reputation lookups and comparison","It automatically submits the sample to law enforcement, which responders are not permitted to do"], correct:0, explanation:"Running malware on a personal workstation risks infection and spread; the performance claim is wrong because malware does not improve a system." },
  { id:80630, domain:3, level:2, question:"What is the purpose of quarantining a file flagged by antivirus?", options:["To permanently encrypt the file so that only the antivirus vendor can ever open it again later","To isolate the suspicious file so it cannot execute while allowing analysis or safe removal","To immediately email the file to every user so they can help decide whether it is malicious","To grant the file additional privileges so it can be studied while running with full access"], correct:1, explanation:"Quarantine isolates a file to prevent execution pending action; granting it privileges is wrong because that would enable, not neutralize, the threat." },
  { id:80631, domain:3, level:2, question:"Which practice best supports rapid recovery after a destructive malware incident?", options:["Storing the only copy of critical data on the same host that is most likely to be infected first","Relying on users to remember file contents from memory so data can be retyped after an attack","Maintaining tested, current backups and a documented restoration procedure kept up to date","Assuming the malware will restore any files it damages once the ransom has been fully paid off"], correct:2, explanation:"Tested current backups plus a restore procedure enable recovery; storing the only copy on the at-risk host is wrong because it offers no protection." },
  { id:80632, domain:3, level:2, question:"What role does user awareness training play in malware prevention?", options:["It replaces every technical control because trained users make all endpoint protection unnecessary","It guarantees that phishing emails will be blocked at the gateway before reaching any inbox","It automatically patches operating system vulnerabilities that attackers use to deliver malware","It reduces the chance users open malicious attachments or links that lead to malware infections"], correct:3, explanation:"Awareness training lowers the odds users trigger infections; claiming it replaces technical controls is wrong because layered defenses are still needed." },
  { id:80633, domain:3, level:2, question:"Which of the following is an appropriate eradication step after confirming a trojan on a host?", options:["Removing the malware, its persistence, and dropped files, then patching the exploited weakness","Reconnecting the host to the network immediately so users are not inconvenienced during cleanup","Leaving the trojan in place but disabling logging so its activity no longer appears in any alerts","Assuming the trojan is harmless because it disguised itself as a legitimate business application"], correct:0, explanation:"Eradication removes malware, persistence, and closes the vector; disabling logging is wrong because it hides activity without removing the threat." },
  { id:80634, domain:3, level:2, question:"Why is identifying the initial infection vector important during malware incident handling?", options:["It determines the exact resale price the organization can charge for the compromised hardware","It reveals how the malware entered so the same weakness can be closed to prevent recurrence","It is required only to assign personal blame and has no effect on preventing future infections","It allows responders to skip containment because the vector alone stops all further spread"], correct:1, explanation:"Finding the vector lets responders close it to prevent recurrence; assigning blame is wrong because that does not improve future security." },
  { id:80635, domain:3, level:2, question:"Which detection signal would most strongly suggest ransomware activity in progress?", options:["A single user printing a large document to the shared office printer during business hours","A scheduled antivirus scan running quietly overnight during the approved maintenance window","A sudden surge of file renames or extension changes across many directories in a short time","A routine password change performed by a user through the approved self-service portal page"], correct:2, explanation:"Mass file renames or extension changes signal encryption; a single print job is wrong because it does not indicate mass file modification." },
  { id:80636, domain:3, level:2, question:"What is the recommended handling for a USB drive suspected of carrying malware?", options:["Plug it directly into a critical production server to quickly check whether it works properly","Share it among several users so each can help determine whether the drive is really infected","Format it immediately without analysis so that any evidence of the infection is destroyed fast","Scan it in an isolated environment and disable autorun before connecting it to any host"], correct:3, explanation:"Scanning in isolation with autorun disabled is safe; plugging it into a production server is wrong because it risks infecting a critical system." },
  { id:80637, domain:3, level:2, question:"Which measure most directly limits a worm's ability to spread across an internal network?", options:["Segmenting the network and restricting unnecessary services like open file-sharing between hosts","Increasing the desktop screen brightness so users notice the worm's activity more quickly","Encrypting individual user documents, which prevents a worm from moving between the hosts","Installing more physical printers so network traffic from the worm is spread more thinly out in this case"], correct:0, explanation:"Segmentation and closing unneeded services limit worm spread; document encryption is wrong because it does not stop network propagation." },
  { id:80638, domain:3, level:2, question:"Why is it important to determine the malware family during analysis?", options:["Knowing the family lets responders skip containment because the family name stops the spread","Known families have documented behaviors, IOCs, and sometimes decryptors that guide response","The family name is legally required on the invoice sent to the attacker requesting the ransom","Identifying the family automatically restores all encrypted files to their original readable state"], correct:1, explanation:"Family identification supplies known behaviors, IOCs, and possible decryptors; the auto-restore claim is wrong because a name cannot decrypt files." },
  { id:80639, domain:3, level:2, question:"Which action supports post-incident improvement after a malware event?", options:["Deleting all incident records so the organization is not reminded of the past malware event","Assuming no changes are needed because the incident was successfully contained and eradicated in this case","Conducting a lessons-learned review and updating playbooks, controls, and training accordingly","Reconnecting all systems without validation to prove the organization has fully moved on now"], correct:2, explanation:"A lessons-learned review that updates controls drives improvement; deleting records is wrong because it erases the basis for learning." },
  { id:80640, domain:3, level:2, question:"What is a reasonable containment action when malware is detected on a domain controller?", options:["Immediately power it off with no assessment, ignoring the authentication services it provides","Leave it fully online and untouched because domain controllers can never actually be infected","Reconnect it to more networks so its logs are distributed widely before any containment begins in this case","Isolate it carefully, assess dependency impact, and involve senior responders due to its critical role"], correct:3, explanation:"Careful isolation with impact assessment fits a critical DC; abrupt power-off with no assessment is wrong because it can disrupt authentication broadly." },
  { id:80641, domain:3, level:2, question:"Why should antivirus and EDR signatures and rules be kept up to date?", options:["Updated definitions and behavioral rules improve detection of newly discovered malware threats","Updates make the software run slower, which is desirable because malware also runs more slowly","Updating removes the need for backups because up-to-date tools can recover any encrypted data","Updating guarantees complete immunity so no incident response process is ever needed again"], correct:0, explanation:"Current signatures and rules catch newer threats; the immunity claim is wrong because no tool provides complete protection on its own." },
  { id:80642, domain:3, level:2, question:"Which of the following best supports detecting malware through anomaly-based methods?", options:["Waiting until a user manually reports that something on their computer feels a little slow today","Baselining normal system and network behavior, then alerting on significant deviations from it","Matching only exact file names against a fixed list of previously banned program titles again","Counting the total number of emails each employee sends during a typical eight-hour workday"], correct:1, explanation:"Baselining and alerting on deviations supports anomaly detection; exact-name matching is wrong because that is a weak signature-style approach." },
  { id:80643, domain:3, level:2, question:"What is the benefit of collecting volatile data early in a malware investigation?", options:["Volatile data is the only evidence that never changes, so it can be safely collected last of all","Collecting it first automatically removes the malware from memory and cleans the host quickly","Volatile data such as running processes, memory, and connections disappears when power is lost","Volatile data is irrelevant to malware and is collected only for hardware troubleshooting tasks"], correct:2, explanation:"Volatile data vanishes on power loss so it is collected early; calling it never-changing is wrong because it is the most transient evidence." },
  { id:80644, domain:3, level:2, question:"Which of the following describes a suitable use of a honeypot in malware defense?", options:["Storing the organization's only production backups so malware cannot possibly reach them there","Serving as the primary email gateway that all legitimate business mail must pass through daily","Acting as the main domain controller that authenticates every user in the entire organization","Deploying a decoy system to attract, detect, and study attacker and malware behavior safely"], correct:3, explanation:"A honeypot is a decoy for studying attacks; using it as the primary backup store is wrong because a decoy is not a reliable production system." },
  { id:80645, domain:3, level:2, question:"Why should responders preserve malware samples rather than immediately deleting them?", options:["Samples enable analysis for IOCs, attribution, and detection rules that strengthen future defense","Samples must be kept so the attacker can retrieve their malware if they later request it back","Deleting a sample would automatically decrypt any files the malware had previously encrypted","Samples are legally required to be published publicly within one hour of their initial discovery in this case"], correct:0, explanation:"Preserved samples support analysis and detection rule creation; the attacker-retrieval reason is wrong and serves no defensive purpose." },
  { id:80646, domain:3, level:2, question:"What is an appropriate response when EDR flags a suspicious process but is uncertain?", options:["Immediately ignore the alert because uncertain EDR alerts are always harmless false positives","Investigate the process, its parent, network activity, and file origin before deciding to act on it","Grant the process administrator rights so it can finish whatever task it was trying to perform in this case","Broadcast the alert to all employees and ask them to vote on whether the process is malicious"], correct:1, explanation:"Investigating the process context before acting is correct; ignoring uncertain alerts is wrong because it may miss a genuine infection." },
  { id:80647, domain:3, level:2, question:"Which factor most influences whether to clean or reimage a malware-infected system?", options:["The color of the desktop wallpaper the user had configured before the infection was detected","The number of unrelated documents the user happened to have open at the time of the alert","The depth of the infection and confidence that all malicious components can be fully removed","Whether the organization prefers the sound of the word clean over the word reimage that day"], correct:2, explanation:"Infection depth and cleanup confidence drive the decision; wallpaper color is wrong because it is irrelevant to remediation choices." },
  { id:80648, domain:3, level:2, question:"What is the purpose of blocking known malicious IPs and domains at the perimeter?", options:["It permanently prevents any employee from ever sending or receiving legitimate business email in this case","It automatically removes all installed malware from every host inside the corporate network","It guarantees the organization will never again receive any phishing email of any kind at all","It disrupts malware command-and-control and prevents infected hosts from reaching attacker servers"], correct:3, explanation:"Perimeter blocking disrupts C2 and downloads; the auto-removal claim is wrong because blocking traffic does not clean already-infected hosts." },
  { id:80649, domain:3, level:2, question:"Which of these is a preparation activity that improves ransomware resilience specifically?", options:["Implementing and regularly testing offline, immutable backups with a documented restore process","Waiting until ransomware strikes and then deciding for the first time how backups should work","Storing backups only on a network share that every user and every service can freely write to","Relying entirely on paying ransoms as the organization's sole strategy for recovering lost data"], correct:0, explanation:"Tested offline immutable backups build resilience; storing backups on a writable share is wrong because ransomware could encrypt them too." },
  { id:80650, domain:3, level:2, question:"What is the benefit of correlating alerts from multiple sources during a malware incident?", options:["It slows the investigation down deliberately so the incident lasts longer and looks more serious","It builds a fuller picture of the attack, reducing false positives and revealing the true scope","It removes the need to contain any host because correlation alone stops the malware from spreading","It guarantees the attacker's real-world identity will be discovered within the first few minutes"], correct:1, explanation:"Correlation improves accuracy and scope understanding; claiming it removes the need for containment is wrong because analysis does not contain malware." },
  { id:80651, domain:3, level:2, question:"Why is it risky to rely solely on antivirus for malware defense?", options:["Antivirus is the single control that provides complete protection, so nothing else is ever needed","Antivirus automatically encrypts files, which frequently conflicts with ransomware's own encryption","Signature-based antivirus can miss new, fileless, or heavily obfuscated malware variants entirely","Antivirus can only run on servers and therefore cannot protect any user workstations at all ever"], correct:2, explanation:"AV alone misses novel, fileless, or obfuscated threats; calling it complete protection is wrong because layered defenses are necessary." },
  { id:80652, domain:3, level:2, question:"Which action helps confirm that a host is clean before returning it to production?", options:["Asking the user whether the computer subjectively feels faster than it did before the incident","Checking only that the desktop icons are arranged the same way they were before the infection","Confirming that the ransom note has been deleted, which by itself proves the host is fully clean","Rescanning with updated tools, reviewing for persistence, and monitoring behavior after cleanup"], correct:3, explanation:"Rescanning, persistence review, and post-cleanup monitoring confirm cleanliness; deleting the ransom note is wrong because it does not prove removal." },
  { id:80653, domain:3, level:2, question:"What is the role of network monitoring in detecting botnet activity?", options:["It can spot repeated beaconing and connections to command-and-control servers over time","It physically disconnects infected hosts the instant any suspicious network packet is observed","It encrypts all internal traffic so that botnet commands can no longer be read by the attacker","It replaces endpoint protection entirely because monitoring alone removes bots from every host"], correct:0, explanation:"Monitoring spots beaconing and C2 connections; claiming it auto-disconnects hosts is wrong because monitoring detects but does not itself isolate." },
  { id:80654, domain:3, level:2, question:"Which statement about eradication and recovery ordering is correct?", options:["Recovery must always fully complete before any eradication of the malware is even attempted","Eradication removes the malware and its cause before recovery restores and validates the systems","Eradication and recovery are the same single step and are never performed in any sequence at all","Recovery involves executing the malware again to confirm that eradication truly worked correctly"], correct:1, explanation:"Eradication precedes recovery; the claim recovery comes first is wrong because restoring systems before removing malware invites reinfection." },
  { id:80655, domain:3, level:2, question:"Why should critical patches be prioritized on internet-facing systems?", options:["Internet-facing systems can never be infected, so patching them is purely a compliance formality","Patching them makes them slower, which conveniently discourages attackers from targeting them","These systems are directly exposed and are common entry points for malware exploiting known flaws","Internal systems face far more direct exposure, so internet-facing systems are the lowest priority"], correct:2, explanation:"Exposed systems are prime entry points, so their patches are prioritized; calling them un-infectable is wrong because exposure raises their risk." },
  { id:80656, domain:3, level:2, question:"What should a malware incident's severity classification take into account?", options:["Only the file size of the malware sample, regardless of what systems or data it actually affects","Solely the time of day the alert fired, with midnight alerts always rated as the most severe ones","The personal preference of whichever responder happens to open the ticket first that morning","The affected systems' criticality, data sensitivity, spread, and business impact of the infection"], correct:3, explanation:"Severity considers criticality, sensitivity, spread, and impact; using only file size is wrong because size does not reflect actual harm." },
  { id:80657, domain:3, level:2, question:"Which of the following is a sound practice for handling a widespread malware outbreak?", options:["Activating the incident response plan, coordinating teams, and containing affected segments quickly","Having each employee independently improvise their own personal response with no coordination","Waiting several days to see whether the outbreak resolves itself before taking any real action in this case","Publicly disclosing every technical detail immediately before the incident is even understood"], correct:0, explanation:"Activating the plan and coordinating containment is sound; uncoordinated improvisation is wrong because it leads to inconsistent, ineffective response." },
  { id:80658, domain:3, level:2, question:"Why is asset inventory important for malware incident handling?", options:["An inventory automatically removes malware from any listed asset the moment it becomes infected","Knowing what systems exist and their criticality helps scope, prioritize, and contain infections","It is used only to calculate depreciation and has no relevance to any incident response activity","It guarantees that unlisted shadow-IT systems are always immune to any malware infection at all"], correct:1, explanation:"Inventory supports scoping and prioritization; the auto-removal claim is wrong because a list of assets cannot clean infected systems." },
  { id:80659, domain:3, level:2, question:"What is a benefit of isolating malware analysis to a dedicated, segregated environment?", options:["It ensures the malware runs faster so that analysts can finish their investigation more quickly","It automatically shares the live malware with all production hosts to test their defenses at once","It prevents accidental infection of production systems while allowing safe study of the sample","It removes the need to ever isolate or contain infected production hosts during a real incident"], correct:2, explanation:"A segregated lab protects production during analysis; sharing malware with production hosts is wrong because that spreads the infection." },
  { id:80660, domain:3, level:2, question:"Which approach best reduces the risk of drive-by-download malware from compromised websites?", options:["Increasing the browser window size so users can more easily see the entire malicious web page","Disabling all backups so that infected browser data is never accidentally restored to a host","Allowing every website to run unrestricted scripts to ensure pages always load without any errors","Keeping browsers and plugins patched and using web filtering to block known malicious sites"], correct:3, explanation:"Patched browsers plus web filtering reduce drive-by risk; allowing unrestricted scripts is wrong because it increases exposure to malicious code." },
  { id:80661, domain:3, level:2, question:"Why should responders coordinate with legal and communications teams during major malware incidents?", options:["To meet notification obligations and manage disclosure while preserving evidence appropriately","To decide together which employee should personally be fired for causing the malware infection","To negotiate a group discount on the ransom payment demanded by the attacker behind the incident","To ensure the technical response is delayed until every legal document has been fully finalized"], correct:0, explanation:"Coordination meets notification duties and manages disclosure; using it to assign blame is wrong because that is not the purpose of such coordination." },
  { id:80662, domain:3, level:2, question:"What is the main goal of the identification step in the incident handling lifecycle?", options:["Permanently removing the malware from every host before the incident has even been confirmed","Confirming whether an event is a genuine malware incident and understanding its initial scope","Restoring all systems to normal operation before determining whether an incident occurred at all","Writing the final report and closing the incident before any analysis has actually taken place"], correct:1, explanation:"Identification confirms a real incident and its scope; removing malware first is wrong because that is eradication, which comes later." },
  { id:80663, domain:3, level:2, question:"Which of the following is a legitimate reason to capture full network packet data during an incident?", options:["It automatically blocks the malware's traffic the moment the first packet has been captured","It encrypts the attacker's traffic so that it can no longer be read by the attacker themselves","It provides detailed evidence of malware communication, exfiltration, and command-and-control","It removes the malware from any host that appears as a source address in the captured traffic"], correct:2, explanation:"Full packet capture gives detailed evidence of malware comms; the auto-block claim is wrong because capturing traffic does not block it." },
  { id:80664, domain:3, level:2, question:"Why is timely internal communication important during an active malware incident?", options:["It ensures the malware author is promptly notified that their attack has been detected and handled","It replaces the technical containment and eradication work with status meetings and update emails","It guarantees that the affected systems will recover on their own without any responder involvement in this case","It keeps stakeholders informed and coordinates containment, avoiding conflicting or duplicated actions"], correct:3, explanation:"Timely communication coordinates response and avoids conflicting actions; notifying the attacker is wrong because that aids, not defends against, them." },
  { id:80665, domain:3, level:2, question:"What is the purpose of scanning all endpoints for IOCs after confirming one malware infection?", options:["To identify any other hosts already compromised so the full scope of the incident is known","To immediately delete every file on all endpoints so the malware has nowhere left to hide at all","To prove the first infected host was actually the only machine that could ever be compromised","To reset all user passwords automatically, which by itself removes malware from every endpoint"], correct:0, explanation:"Sweeping for IOCs finds other compromised hosts and reveals scope; deleting all files is wrong because it is destructive and unnecessary." },
  { id:80666, domain:3, level:2, question:"Which practice reduces the likelihood that spyware silently exfiltrates data from endpoints?", options:["Increasing monitor brightness so users can visually spot data leaving their screen as it happens","Monitoring outbound connections and using DLP and egress filtering to detect and block exfiltration","Disabling all endpoint logging so spyware produces no records that could slow the investigation","Allowing unrestricted outbound traffic so that security tools never interfere with any application in this case"], correct:1, explanation:"Egress monitoring, DLP, and filtering catch exfiltration; allowing unrestricted outbound traffic is wrong because it lets spyware exfiltrate freely." },
  { id:80667, domain:3, level:3, question:"A handler finds malware persisting via a scheduled task that re-downloads a payload after removal. What is the correct fix?", options:["Delete only the downloaded payload each time and leave the scheduled task in place for later study","Reboot the host repeatedly, trusting that the scheduled task will eventually stop running on its own","Remove the scheduled task and payload, then block the download source and close the entry vector","Reconnect the host to the internet so the scheduled task can finish downloading and self-terminate"], correct:2, explanation:"Removing the task and payload plus blocking the source stops re-download; deleting only the payload is wrong because the task will fetch it again." },
  { id:80668, domain:3, level:3, question:"An organization sees identical malware IOCs on both a laptop and a file server. How should scope be handled?", options:["Handle each device as a completely separate incident with no coordination between the two teams","Remediate only the laptop and assume the file server cleaned itself once the laptop was fixed","Ignore the file server because servers are inherently immune to the malware that hit the laptop","Treat both as part of one incident, hunt for other affected hosts, and contain them together"], correct:3, explanation:"Shared IOCs mean a single incident to be scoped broadly; treating them separately is wrong because it fragments a coordinated response." },
  { id:80669, domain:3, level:3, question:"A ransomware sample is identified as a variant with a publicly released decryptor. What should the handler do?", options:["Verify the variant, obtain the trusted decryptor, and test it on copies before recovering data","Pay the ransom anyway to be safe, since decryptors from third parties can never be trusted at all","Apply the decryptor directly to the only remaining copy of the data without any prior testing","Delete all encrypted files first, then run the decryptor on the empty folders to rebuild the data"], correct:0, explanation:"Verifying and testing a trusted decryptor on copies is correct; applying it to the only copy untested is wrong because failure would lose the data." },
  { id:80670, domain:3, level:3, question:"A host beacons to a C2 domain only every 24 hours, making it hard to spot. What detection strategy helps most?", options:["Watching the host for exactly one minute and concluding it is clean if no beacon occurs then","Long-term traffic analysis and threat-intel matching to reveal low-and-slow beaconing patterns","Relying only on the user to notice and report the once-daily connection to the malicious domain","Assuming infrequent beaconing means the malware is dormant and therefore requires no response"], correct:1, explanation:"Long-term analysis and intel matching expose slow beaconing; a one-minute check is wrong because it will likely miss the daily beacon." },
  { id:80671, domain:3, level:3, question:"After containment, an analyst must prioritize which infected systems to remediate first. What is the best basis?", options:["The alphabetical order of the infected computers' hostnames as they appear in the asset list","Whichever infected machine has the fastest processor, since it will finish remediation soonest","Business criticality, data sensitivity, and the risk each infected system poses to the organization","The seating location of each affected user relative to the incident responder's own office desk in this case"], correct:2, explanation:"Prioritizing by criticality, sensitivity, and risk is sound; alphabetical hostname order is wrong because it ignores actual business impact." },
  { id:80672, domain:3, level:3, question:"A macro-enabled document triggers a PowerShell download cradle when opened. Which control would have best prevented this?", options:["Increasing the recipient's mailbox storage quota so the malicious document has more room to run","Encrypting the document at rest, which stops its embedded macro from ever executing when opened","Allowing all macros to run automatically so users are never interrupted by a security warning again","Disabling macros by default and restricting or logging PowerShell execution through policy controls"], correct:3, explanation:"Disabling macros and controlling PowerShell prevents the cradle; allowing all macros is wrong because it maximizes exposure to this exact attack." },
  { id:80673, domain:3, level:3, question:"An incident shows malware spread after a user reused an admin password across many servers. What is the key lesson?", options:["Enforce unique privileged credentials and least privilege to limit lateral movement after infection","Require all users to memorize a single shared admin password so support can move between hosts fast","Remove all passwords entirely so that malware has no credentials left to steal or reuse anywhere","Accept credential reuse as unavoidable and focus solely on paying ransoms after each future incident"], correct:0, explanation:"Unique privileged credentials and least privilege curb lateral movement; a shared password is wrong because reuse is exactly what enabled the spread." },
  { id:80674, domain:3, level:3, question:"A handler discovers exfiltration to an external server during a malware incident. What should be prioritized alongside containment?", options:["Ignoring the exfiltration entirely because only encryption, never data theft, matters in incidents","Assessing what data was taken and meeting any breach notification and legal obligations promptly","Immediately paying the attacker so they promise to delete the stolen data they already exfiltrated","Deleting the affected server's logs so the exfiltration cannot be traced back to the organization"], correct:1, explanation:"Assessing stolen data and meeting notification duties is essential; deleting logs is wrong because it destroys evidence and may violate obligations." },
  { id:80675, domain:3, level:3, question:"An EDR isolates a host automatically upon detecting ransomware. What should the responder verify before restoring it?", options:["That the user has agreed to be more careful in the future before the host is allowed back online","That the ransom has been paid so the attacker consents to the host rejoining the network again","That the malware and persistence are removed and the entry vector is closed before reconnecting","That the host's clock is set correctly, which by itself confirms the ransomware has been removed"], correct:2, explanation:"Verifying malware removal and a closed vector is required before restoring; the clock check is wrong because it does not confirm remediation." },
  { id:80676, domain:3, level:3, question:"A sample uses process hollowing to run malicious code inside a legitimate process. Why is this challenging to detect?", options:["The technique always crashes the host immediately, which makes any subsequent detection impossible","Process hollowing only works on printers, so endpoint detection tools never look for it on computers in this case","The technique writes a large obvious file to the desktop, which analysts routinely overlook by habit","The malicious code executes under the identity of a trusted process, blending in with normal activity"], correct:3, explanation:"Hollowing hides code inside a trusted process, blending with normal activity; the immediate-crash claim is wrong because stealth, not crashing, is the goal." },
  { id:80677, domain:3, level:3, question:"During analysis, malware is found reaching out to a legitimate cloud storage service for its payload. Why do attackers do this?", options:["Legitimate services blend with normal traffic and are less likely to be blocked by defenders","Cloud services are legally required to host and distribute any malware payload uploaded to them","Using cloud storage automatically encrypts the payload so that defenders can never analyze it","Attackers do this only to increase their own cloud storage bills as a form of financial protest"], correct:0, explanation:"Trusted cloud services blend with normal traffic and evade blocking; the legal-requirement claim is wrong and not why attackers abuse them." },
  { id:80678, domain:3, level:3, question:"A responder must handle malware on a system that also holds evidence for another investigation. What should they do?", options:["Wipe the system immediately to remove the malware, disregarding the unrelated ongoing investigation","Preserve forensic evidence properly, coordinating with stakeholders before any remediation actions","Ignore the malware entirely so the other investigation's evidence remains completely untouched forever","Publicly post the disk image online so multiple investigators can review the evidence in parallel"], correct:1, explanation:"Preserving evidence and coordinating first is correct; wiping immediately is wrong because it destroys evidence needed for the other investigation." },
  { id:80679, domain:3, level:3, question:"A ransomware attack encrypted files, but the organization restored from immutable backups within hours. What made this possible?", options:["The ransomware chose not to encrypt the backups because it only ever targets user desktop files","The antivirus decrypted the backups automatically during the restore, so no clean copies were needed","Backups were isolated and immutable, so the ransomware could not alter or encrypt those copies","The backups were stored on the same infected server, which is why they survived the attack intact"], correct:2, explanation:"Isolated immutable backups survived the attack, enabling fast restore; the same-server claim is wrong because reachable backups would also be encrypted." },
  { id:80680, domain:3, level:3, question:"A worm is spreading via an exploited unpatched vulnerability. Which combination stops it most effectively?", options:["Only telling users to reboot their machines, which permanently removes the worm from the network","Increasing bandwidth so the worm's scanning traffic no longer noticeably slows the network down","Waiting for the worm to run out of new hosts to infect before taking any technical action at all","Patching the vulnerability, segmenting the network, and isolating and cleaning infected hosts"], correct:3, explanation:"Patching, segmenting, and cleaning hosts together stop the worm; rebooting alone is wrong because it does not fix the exploited vulnerability." },
  { id:80681, domain:3, level:3, question:"An analyst notes malware disables Windows Defender and clears event logs on infection. What is the attacker's intent?", options:["Defense evasion and anti-forensics to avoid detection and hinder later investigation of the intrusion","Routine system maintenance that legitimately frees disk space by removing old, unneeded log data","A helpful diagnostic feature intended to make the responder's forensic analysis faster and easier","An accidental side effect of the malware that provides the attacker with no real operational benefit in this case"], correct:0, explanation:"Disabling defenses and clearing logs is defense evasion and anti-forensics; calling it routine maintenance is wrong because it deliberately hinders response." },
  { id:80682, domain:3, level:3, question:"A handler suspects a fileless attack but finds nothing malicious on disk. Where should they focus the investigation?", options:["Only the list of files on the disk, since all malware must always leave a file somewhere on disk","Memory, running processes, script interpreters, and command-line and PowerShell logging artifacts","The physical condition of the hard drive, since fileless malware corrupts the drive's platters directly","The printer queue, because fileless malware executes exclusively through print jobs on the network"], correct:1, explanation:"Fileless attacks live in memory, processes, and script logs; focusing only on disk files is wrong because fileless malware leaves little on disk." },
  { id:80683, domain:3, level:3, question:"An organization wants to reduce successful phishing-delivered malware. Which layered approach is strongest?", options:["Rely on a single spam filter alone, since one well-configured control fully eliminates phishing risk","Depend solely on users to detect every phishing email without any supporting technical controls","Combine email filtering, attachment sandboxing, user training, and endpoint protection together","Block all email permanently, since removing email entirely is the only realistic way to reduce risk"], correct:2, explanation:"Layered filtering, sandboxing, training, and endpoint defense is strongest; relying on one filter alone is wrong because no single control catches everything." },
  { id:80684, domain:3, level:3, question:"A malware incident is contained, but forensic analysis is still ongoing. When should the final report be issued?", options:["Immediately upon containment, even though the root cause and full scope are still unknown at that point","Only after several years, so that the incident is safely forgotten before anything is documented","Never, because documenting incidents provides no value once the malware has been contained already","After analysis concludes, so the report accurately reflects root cause, scope, and lessons learned"], correct:3, explanation:"The final report follows completed analysis for accuracy; issuing it before knowing root cause is wrong because it would be incomplete and misleading." },
  { id:80685, domain:3, level:3, question:"A handler observes that infected hosts all visited the same compromised website before infection. This suggests what attack type?", options:["A watering-hole attack, where a site the targets commonly visit is compromised to deliver malware","A brute-force attack, where the attacker repeatedly guessed each host's login credentials directly","A physical attack, where the attacker manually inserted infected media into each affected machine","A denial-of-service attack, which flooded the website rather than using it to deliver any malware"], correct:0, explanation:"A shared compromised site infecting visitors is a watering-hole attack; brute force is wrong because no credential guessing is involved here." },
  { id:80686, domain:3, level:3, question:"During recovery, some restored files are suspected of still containing malicious macros. What should be done?", options:["Restore everything without any scanning, since backups are always guaranteed to be completely clean","Scan and validate restored data for malicious content before returning it to normal production use","Delete all restored files immediately so that the suspicious macros can never possibly execute again","Reconnect the systems to the network first and rely on users to report any macros that misbehave"], correct:1, explanation:"Scanning and validating restored data prevents reintroducing malware; restoring without scanning is wrong because backups can contain infected files." },
  { id:80687, domain:3, level:3, question:"A malware campaign uses signed but malicious drivers to gain kernel access. Why is this especially dangerous?", options:["Signed drivers are automatically deleted by the operating system, so they pose no real threat at all","Kernel drivers can only display advertisements and are therefore among the least harmful malware types","Kernel-level code can disable security tools and hide deeply, making detection and removal very hard","Signed drivers run with the fewest privileges on the system, limiting the damage they can ever do"], correct:2, explanation:"Kernel access lets malware disable defenses and hide deeply; claiming signed drivers are auto-deleted is wrong because the OS trusts valid signatures." },
  { id:80688, domain:3, level:3, question:"A responder needs to determine whether data was exfiltrated by malware. Which artifacts are most useful?", options:["The desktop wallpaper history, which reliably records every file the malware ever sent externally","The number of times the user opened the calculator application during the infection time window","The physical weight of the server chassis, which increases measurably when data is exfiltrated","Outbound network flows, proxy and DNS logs, and evidence of large or unusual data transfers"], correct:3, explanation:"Network flows and proxy/DNS logs reveal exfiltration; wallpaper history is wrong because it records nothing about data leaving the network." },
  { id:80689, domain:3, level:3, question:"After a botnet takedown, an organization still sees beaconing from some hosts. What is the most likely explanation?", options:["Some hosts remain infected and are attempting to reach C2 infrastructure that may be sinkholed now","The takedown accidentally reinfected every clean host on the network with the same botnet malware","Beaconing after a takedown always means the hosts are now completely clean and fully remediated","The hosts are contacting the antivirus vendor to request a refund for the failed botnet protection"], correct:0, explanation:"Continued beaconing means some hosts are still infected and reaching (possibly sinkholed) C2; assuming they are clean is wrong because they clearly are not." },
  { id:80690, domain:3, level:3, question:"A critical server is infected, but taking it offline would halt operations. What containment approach balances the risks?", options:["Leave the server fully connected and completely unmonitored until a convenient time next quarter","Apply network-level restrictions and enhanced monitoring while planning a controlled remediation window","Immediately pull the power with no planning, accepting a total unplanned outage of all operations","Reconnect the server to more networks to distribute its workload while the infection continues to spread"], correct:1, explanation:"Network restrictions plus monitoring and a planned window balance the risks; leaving it unmonitored is wrong because the infection would continue unchecked." },
  { id:80691, domain:3, level:3, question:"A malware sample only activates when it detects a specific keyboard language or region. What is the attacker likely doing?", options:["Optimizing the malware to run faster on keyboards that use that particular language layout only","Providing localized help text so victims in that region can more easily understand the ransom note","Targeting or avoiding specific regions, a tactic used to focus on or spare certain victim populations","Randomly failing to run, since keyboard language has no possible influence on malware execution ever in this case"], correct:2, explanation:"Region-based activation targets or spares specific victims; the random-failure claim is wrong because the check is deliberate targeting, not chance." },
  { id:80692, domain:3, level:3, question:"An incident review finds that detection was delayed because logs were not centralized. What improvement addresses this?", options:["Reduce logging on all endpoints so that responders have fewer log files to sort through later","Store each system's logs only locally so that they are conveniently deleted when a host is reimaged","Rely on users to email their local logs to the response team whenever they suspect an infection","Implement centralized logging and SIEM correlation so malware indicators are detected sooner"], correct:3, explanation:"Centralized logging and SIEM speed detection; storing logs only locally is wrong because it prevents correlation and loses evidence on reimaging." },
  { id:80693, domain:3, level:3, question:"A handler must choose an order for eradication actions on an infected host. Which sequence is most sound?", options:["Preserve needed evidence, remove malware and persistence, close the vector, then validate the host","Reconnect the host to production first, then decide later whether any malware still remains on it in this case","Close the incident ticket first, then begin removing the malware once management has approved it","Reimage without any evidence preservation, then attempt to recover the lost evidence afterward"], correct:0, explanation:"Preserve evidence, remove malware, close the vector, then validate is sound; reconnecting first is wrong because it risks spread before cleanup." },
  { id:80694, domain:3, level:3, question:"A phishing email delivered malware that established persistence and contacted C2 within seconds. What does this speed suggest?", options:["A slow manual attacker who happened to type all of the commands by hand in only a few seconds","An automated, pre-built toolkit executing a scripted infection chain immediately upon user action","A benign application, since fast persistence and C2 contact are normal for legitimate software too","A hardware malfunction that coincidentally created a scheduled task and an external connection"], correct:1, explanation:"Near-instant persistence and C2 point to an automated toolkit; the manual-attacker claim is wrong because no human types that fast." },
  { id:80695, domain:3, level:3, question:"An organization detects cryptomining malware consuming server resources. Beyond removal, what root-cause action matters?", options:["Buying faster servers so the cryptominer's resource usage is no longer noticeable to any user at all in this case","Paying the miner's operator to move their mining activity to a competitor's servers instead of yours","Identifying and closing the exploited weakness or exposed service that allowed the initial compromise","Ignoring the entry point entirely since removing the miner once guarantees it can never return again"], correct:2, explanation:"Closing the exploited entry point prevents recurrence; buying faster servers is wrong because it hides the abuse without fixing the root cause." },
  { id:80696, domain:3, level:3, question:"A responder wants to safely detonate a suspicious executable to observe behavior. What environment is appropriate?", options:["A production database server, so the observed behavior reflects a realistic operational environment","The responder's own daily-use laptop, which is convenient and already has all the analysis tools","A shared kiosk that many employees use, so multiple people can watch the detonation together live","An isolated, instrumented sandbox with no path to production networks or sensitive data at all"], correct:3, explanation:"An isolated instrumented sandbox is appropriate; a production database server is wrong because detonating malware there risks real damage." },
  { id:80697, domain:3, level:3, question:"Malware persists by replacing a legitimate DLL with a malicious one. During eradication, why must the handler restore the original DLL?", options:["Leaving the malicious DLL keeps the malware active and may break the application that depends on it","The malicious DLL will automatically convert itself back into the clean original after the next reboot","Restoring the original DLL is unnecessary because deleting a single unrelated file removes all malware","The malicious DLL is harmless once renamed, so no restoration of the legitimate file is ever required"], correct:0, explanation:"Restoring the clean DLL removes the malware and fixes the app; assuming it self-heals on reboot is wrong because malicious files do not repair themselves." },
  { id:80698, domain:3, level:3, question:"A malware incident affected customer data. Which post-incident obligation is most likely to apply?", options:["Publicly ranking the affected customers by how much of their data the malware managed to steal","Notifying affected individuals and regulators as required by applicable data protection laws","Requiring each affected customer to personally reimburse the organization for its response costs","Deleting all records of which customers were affected so the breach cannot be traced afterward"], correct:1, explanation:"Breach notification to individuals and regulators is a likely obligation; deleting affected-customer records is wrong because it may violate the law." },
  { id:80699, domain:3, level:3, question:"An analyst finds the same malware family targeting several peer organizations in the same sector. What does this suggest?", options:["A pure coincidence with no relationship between the incidents that requires no further attention","Proof that the malware is harmless because it is so widely distributed across many organizations","A coordinated campaign targeting the sector, warranting shared threat intelligence and joint defense","A guarantee that the organization's own systems are immune since peers were infected instead of it in this case"], correct:2, explanation:"Sector-wide targeting indicates a coordinated campaign benefiting from shared intelligence; calling it coincidence is wrong given the correlated targeting." },
  { id:80700, domain:3, level:3, question:"During containment, a responder must decide whether to block a domain that malware and some business apps both use. What is the best approach?", options:["Block the domain instantly with no impact assessment, accepting whatever business disruption results","Never block the domain under any circumstances, even though the malware actively relies upon it","Ask the malware author whether blocking the shared domain would be acceptable to their operation","Assess business impact and use targeted blocking or monitoring to balance security and operations"], correct:3, explanation:"Assessing impact and using targeted controls balances the trade-off; blocking blindly is wrong because it may disrupt critical business operations." },
];
